export const socialWorkEntriesSupplement: EncyclopediaEntry[] = [
  // ===== CHILD WELFARE =====
  e("child-abuse-reporting", "Mandated Reporting of Child Abuse", "Child Welfare", "Mandated Reporting in Social Work | ASWB Exam Guide", "Learn about mandated reporting obligations and child abuse indicators for the ASWB exam.", ["mandated reporting", "child abuse", "child neglect", "CPS", "ASWB"], "Social workers are mandated reporters of child abuse and neglect in all 50 states. Mandated reporting requires reporting suspected abuse or neglect whenever there is reasonable suspicion. Proof is not required.", "Child maltreatment categories include physical abuse, sexual abuse, emotional abuse, and neglect. Neglect is the most common form. The reasonable suspicion standard means reporting when information would lead a reasonable person to suspect maltreatment.", "Mandated reporting is one of the most frequently tested ASWB exam topics. The duty to report overrides client confidentiality.", "Physical abuse indicators include unexplained injuries, burns with distinctive patterns, fractures inconsistent with developmental stage. Neglect indicators include poor hygiene, malnutrition, chronic absenteeism, inadequate supervision.", "Assessment involves identifying indicators, interviewing the child separately, documenting observations, and making a CPS report. The reporter's role is to report, not investigate.", "Report to CPS immediately. Document observations and statements. Provide support to the child and family. Cooperate with investigation. Mandated reporters have legal immunity for good-faith reports.", "Failure to report constitutes a criminal offense. Investigating before reporting delays protection. Notifying the alleged perpetrator can endanger the child.", ["Report based on reasonable suspicion, not proof", "Neglect is the most common form of maltreatment", "Mandated reporting overrides client confidentiality", "Reporters have legal immunity for good-faith reports"], ["Waiting for proof before reporting", "Investigating rather than reporting to CPS", "Notifying the alleged perpetrator before making a report"], [{question: "When must a social worker report suspected child abuse?", answer: "Whenever there is reasonable suspicion of abuse or neglect. Proof or certainty is not required."}, {question: "Does mandated reporting override confidentiality?", answer: "Yes. The duty to report child abuse is a legally recognized exception to client confidentiality."}]),

  e("adoption-in-social-work", "Adoption", "Child Welfare", "Adoption in Social Work Practice | ASWB Exam Guide", "Learn about adoption processes, types, and social work roles for the ASWB exam.", ["adoption", "permanency", "open adoption", "MEPA", "ASWB"], "Adoption is the legal process by which a person becomes the lawful parent of a child not their biological offspring. Social workers conduct home studies, provide counseling, and support adoptive families.", "Types include domestic infant adoption, foster care adoption, international adoption (Hague Convention), kinship adoption, and stepparent adoption. Open adoption involves ongoing birth family contact. MEPA prohibits delaying placement based on race; ICWA provides protections for Native American children.", "Adoption is tested on the ASWB exam in permanency planning and child welfare contexts.", "Adopted children may experience identity questions, grief, attachment challenges. Adoptive parents may face adjustment stress. Birth parents may experience grief and loss.", "Assessment includes home study evaluations, child assessment, and post-placement supervision.", "Pre-adoption education, post-adoption support, family therapy, life book work, and search/reunion assistance.", "Failing to address adoption-related grief and identity issues can cause long-term adjustment problems.", ["MEPA prohibits delaying placement based on race", "ICWA provides specific protections for Native American children", "Open adoption is increasingly supported by research", "Adoption creates lifelong identity and relationship considerations"], ["Confusing MEPA with ICWA", "Not recognizing adoption-related grief", "Assuming closed adoption is always preferable"], [{question: "What is MEPA?", answer: "The Multiethnic Placement Act prohibits delaying or denying foster care or adoption placement based on race, color, or national origin."}, {question: "What is the difference between open and closed adoption?", answer: "Open adoption involves ongoing contact between birth and adoptive families. Closed adoption seals identifying information. Research increasingly supports open adoption."}]),

  e("child-development-milestones", "Child Development Milestones", "Child Welfare", "Child Development Milestones | ASWB Exam Guide", "Learn about developmental milestones and their relevance to social work for the ASWB exam.", ["child development", "milestones", "developmental delays", "ASWB"], "Understanding child development milestones is fundamental to social work practice. Milestones are behavioral or physical markers across motor, language, cognitive, and social-emotional domains.", "Motor: head control (2-4 mo), sitting (6 mo), walking (12 mo). Language: cooing (2-3 mo), babbling (6-9 mo), first words (12 mo), two-word phrases (24 mo). Social: social smiling (2 mo), stranger anxiety (8-9 mo), parallel play (2 yr), cooperative play (4-5 yr).", "ASWB tests knowledge of normal milestones and effects of maltreatment on development.", "Red flags: no babbling by 12 months, no words by 16 months, no phrases by 24 months, loss of acquired skills, not walking by 18 months.", "Screening tools include ASQ (Ages and Stages Questionnaire) and Denver Developmental Screening Test (DDST-II).", "Early intervention referral, developmental therapy, family support, and coordination with pediatric providers.", "Failure to identify delays early leads to missed intervention windows.", ["Milestones follow predictable sequences", "Early identification improves outcomes", "Abuse and neglect can significantly delay development", "Standardized screening tools support consistent assessment"], ["Not knowing age-appropriate milestones", "Confusing parallel play (age 2) with cooperative play (age 4-5)", "Not referring for early intervention when delays are identified"], [{question: "When should a child say their first words?", answer: "Most children say their first words around 12 months. No words by 16 months is a red flag requiring evaluation."}, {question: "What is parallel play?", answer: "Playing alongside but not with other children, typical around age 2. Cooperative play (playing together) develops around age 4-5."}]),

  e("indian-child-welfare-act", "Indian Child Welfare Act (ICWA)", "Child Welfare", "Indian Child Welfare Act | ASWB Exam Guide", "Learn about ICWA provisions and placement preferences for the ASWB exam.", ["ICWA", "Indian Child Welfare Act", "tribal sovereignty", "ASWB"], "ICWA (1978) establishes standards for removal and placement of Native American children, enacted in response to widespread removal of Native American children from their families.", "ICWA gives tribal courts exclusive jurisdiction over children on reservations. Requires active efforts (higher than reasonable efforts) to prevent breakup of Indian families. Placement preferences: (1) extended family, (2) tribal foster home, (3) Indian foster home, (4) tribal institution.", "ICWA is frequently tested on the ASWB exam. Social workers must know placement preferences, active efforts, and tribal notification.", "ICWA proceedings require tribal notification by registered mail, expert witness testimony, clear and convincing evidence for foster care, and beyond reasonable doubt for TPR.", "Social workers must determine early whether a child may be subject to ICWA by asking about tribal affiliation.", "Active efforts to prevent breakup of the Indian family, compliance with placement preferences, and tribal coordination.", "Failure to comply with ICWA can result in invalidation of proceedings.", ["ICWA requires active efforts, a higher standard than reasonable efforts", "Placement preferences prioritize extended family and tribal homes", "Tribal courts have exclusive jurisdiction for children on reservations", "The tribe determines eligibility for membership"], ["Confusing reasonable efforts with active efforts under ICWA", "Not identifying cases subject to ICWA early", "Not notifying the tribe by registered mail"], [{question: "What are ICWA placement preferences?", answer: "In order: extended family, foster home licensed by the tribe, Indian foster home, institution approved by the tribe."}, {question: "What is the difference between reasonable efforts and active efforts?", answer: "Active efforts under ICWA is a higher standard requiring more intensive services to prevent family breakup, beyond the reasonable efforts standard used in non-ICWA cases."}]),

  e("child-sexual-abuse", "Child Sexual Abuse", "Child Welfare", "Child Sexual Abuse Assessment | ASWB Guide", "Learn about child sexual abuse dynamics, assessment, and treatment for the ASWB exam.", ["child sexual abuse", "CSA", "grooming", "disclosure", "ASWB"], "Child sexual abuse involves sexual contact or exploitation of a child by an adult or older child. Social workers must understand the dynamics, assessment approaches, and evidence-based treatment.", "CSA dynamics include grooming (building trust and compliance), secrecy (threats, shame), and Summit's Accommodation Syndrome: secrecy, helplessness, accommodation, delayed disclosure, retraction. Most perpetrators are known to the child.", "CSA assessment and dynamics are tested on the ASWB exam.", "Children may present with behavioral indicators (sexualized behavior, regression, sleep disturbance) rather than direct disclosure. Delayed and incremental disclosure is normal.", "Use developmentally appropriate, non-leading interview techniques. Forensic interviews (NICHD protocol) are conducted by trained professionals. Avoid repeated interviews.", "Trauma-focused CBT is the gold standard treatment. Family support, safety planning, and coordination with CPS and law enforcement.", "Leading questions during assessment can contaminate evidence. Failure to believe the child can cause further harm.", ["Most perpetrators are known to the child", "Delayed disclosure is normal, not evidence of fabrication", "Retraction does not mean abuse did not occur", "Forensic interviews should use non-leading techniques"], ["Assuming stranger perpetrators are most common", "Interpreting delayed disclosure as fabrication", "Using leading questions during assessment"], [{question: "Why do children delay disclosing sexual abuse?", answer: "Fear of consequences, shame, threats from the perpetrator, loyalty to the family, and fear of not being believed. Delayed disclosure is normative, not evidence of fabrication."}, {question: "What is the Accommodation Syndrome?", answer: "Summit's model describing common patterns: secrecy, helplessness, accommodation, delayed disclosure, and retraction."}]),

  e("parental-rights-termination", "Termination of Parental Rights", "Child Welfare", "TPR in Social Work | ASWB Exam Guide", "Learn about TPR proceedings and social work roles for the ASWB exam.", ["TPR", "termination of parental rights", "permanency", "ASFA", "ASWB"], "TPR permanently severs the parent-child relationship and is the most severe action in child welfare, requiring clear and convincing evidence.", "ASFA (1997) requires filing for TPR when a child has been in care for 15 of the most recent 22 months, with exceptions. TPR grounds include abandonment, severe abuse, chronic neglect, parental incapacity, and failure to comply with case plan.", "TPR is tested on the ASWB exam in permanency planning and ASFA timelines.", "Before TPR, reasonable efforts toward reunification must be documented unless aggravated circumstances exist.", "Evaluate parental compliance with case plans, parent-child relationship quality, and child's need for permanency.", "Document case history, provide testimony, support the child, and facilitate permanency planning post-TPR.", "Premature TPR without adequate services violates due process. Delayed TPR leaves children in foster care limbo.", ["ASFA requires TPR filing after 15 of 22 months in care with exceptions", "TPR requires clear and convincing evidence", "Reasonable efforts must precede TPR", "TPR is the most severe action in child welfare"], ["Not knowing ASFA timeline requirements", "Confusing TPR standard of evidence with criminal standards", "Not recognizing exceptions to the 15/22 month rule"], [{question: "What is ASFA?", answer: "The Adoption and Safe Families Act (1997) established timelines for permanency decisions, including requiring TPR filing after 15 of 22 months in foster care."}, {question: "What standard of evidence is required for TPR?", answer: "Clear and convincing evidence, a higher standard than preponderance of evidence but lower than beyond a reasonable doubt."}]),

  e("family-preservation-services", "Family Preservation Services", "Child Welfare", "Family Preservation | ASWB Guide", "Learn about family preservation models for the ASWB exam.", ["family preservation", "Homebuilders", "intensive family services", "ASWB"], "Family preservation services are intensive, time-limited, home-based services designed to prevent unnecessary out-of-home placement.", "The Homebuilders model: 4-6 week intervention, small caseloads (2-3 families), 24/7 availability, in-home services, 40+ hours of contact. Services include crisis intervention, skill building, concrete services, and family therapy.", "Family preservation is tested on the ASWB exam in child welfare practice contexts.", "Families are referred when children are at imminent risk of placement.", "Evaluate safety risks, family strengths, and factors contributing to the crisis.", "Intensive in-home crisis intervention, parent education, skill building, concrete services, family therapy, and community coordination.", "Family preservation is inappropriate when children face imminent danger unmanageable with in-home services.", ["Homebuilders is the most well-known family preservation model", "Services are intensive, time-limited, and home-based", "Small caseloads allow intensive engagement", "Aims to prevent unnecessary out-of-home placement"], ["Confusing family preservation with family reunification", "Not recognizing when safety concerns outweigh preservation", "Not knowing the Homebuilders model"], [{question: "What is the Homebuilders model?", answer: "An intensive family preservation program with 4-6 week duration, small caseloads (2-3 families), 24/7 availability, and 40+ hours of in-home contact."}, {question: "When is family preservation inappropriate?", answer: "When children face imminent danger that cannot be managed safely with in-home services."}]),

  // ===== SUBSTANCE ABUSE =====
  e("co-occurring-disorders", "Co-Occurring Disorders", "Substance Abuse", "Co-Occurring Disorders | ASWB Exam Guide", "Learn about co-occurring mental health and substance use disorders for the ASWB exam.", ["co-occurring disorders", "dual diagnosis", "integrated treatment", "ASWB"], "Co-occurring disorders refer to simultaneous mental health and substance use disorders. Approximately 50% of individuals with severe mental illness also have a substance use disorder.", "Integrated treatment addresses both disorders simultaneously. SAMHSA's integrated model combines mental health and substance abuse interventions. The self-medication hypothesis suggests some individuals use substances to manage psychiatric symptoms.", "Co-occurring disorders are tested on the ASWB exam in substance abuse and mental health contexts.", "Common combinations: depression with alcohol use, PTSD with substance use, bipolar with substance use, anxiety with benzodiazepine/alcohol use.", "Screen for both disorders simultaneously using AUDIT, DAST, PHQ-9, and integrated assessments.", "Integrated treatment is the gold standard. MI, CBT, medication management, peer support, and relapse prevention.", "Treating only one disorder while ignoring the other leads to poor outcomes.", ["Integrated treatment addresses both disorders simultaneously", "COD is the rule, not the exception, in severe mental illness", "Sequential treatment is less effective than integrated", "Self-medication hypothesis explains some co-occurring patterns"], ["Treating substance use and mental health separately", "Not screening for both disorders simultaneously", "Attributing all symptoms to one disorder while missing the other"], [{question: "What is integrated treatment?", answer: "Addressing both mental health and substance use disorders simultaneously by the same treatment team, rather than sequentially or in parallel."}, {question: "What is the self-medication hypothesis?", answer: "The theory that some individuals use substances to manage psychiatric symptoms such as anxiety, depression, or psychotic experiences."}]),

  e("twelve-step-programs", "Twelve-Step Programs", "Substance Abuse", "Twelve-Step Programs | ASWB Exam Guide", "Learn about twelve-step programs and their role in recovery for the ASWB exam.", ["twelve-step", "AA", "NA", "mutual aid", "recovery", "ASWB"], "Twelve-step programs (AA, NA, Al-Anon) are mutual aid groups based on peer support and spiritual principles. They are the most widely available support for substance use disorders.", "AA was founded in 1935 by Bill Wilson and Dr. Bob Smith. Core principles: powerlessness over the substance, higher power, moral inventory, making amends, helping others. Sponsorship provides one-on-one support. Al-Anon and Alateen support family members.", "Twelve-step programs are tested on the ASWB exam in substance abuse and community resource contexts.", "Programs provide fellowship, structure, accountability, and hope. Meetings are free and widely available.", "Assess client readiness for twelve-step involvement, address barriers, and understand alternatives (SMART Recovery, SOS).", "Facilitate referral, address barriers, integrate with professional treatment, support family involvement through Al-Anon.", "Mandating attendance without considering client beliefs may violate self-determination.", ["Twelve-step programs are mutual aid, not professional treatment", "AA was founded in 1935", "Alternatives exist: SMART Recovery, SOS, Women for Sobriety", "Al-Anon supports family members"], ["Treating twelve-step as substitute for professional treatment", "Not recognizing alternatives for clients who object to spiritual components", "Mandating attendance without considering client preferences"], [{question: "Are twelve-step programs professional treatment?", answer: "No. They are mutual aid groups that complement professional treatment but do not replace it."}, {question: "What alternatives exist for clients who object to twelve-step?", answer: "SMART Recovery (cognitive-behavioral), Secular Organizations for Sobriety (SOS), and Women for Sobriety are secular alternatives."}]),

  e("medication-assisted-treatment", "Medication-Assisted Treatment", "Substance Abuse", "MAT in Social Work | ASWB Guide", "Learn about MAT for substance use disorders for the ASWB exam.", ["MAT", "methadone", "buprenorphine", "naltrexone", "ASWB"], "MAT combines FDA-approved medications with counseling for substance use disorders, particularly opioid and alcohol use disorders. MAT is evidence-based and reduces mortality and relapse.", "Opioid MAT: methadone (full agonist, licensed clinics), buprenorphine/Suboxone (partial agonist, certified providers), naltrexone/Vivitrol (antagonist, blocks effects). Alcohol MAT: naltrexone (reduces craving), acamprosate (withdrawal discomfort), disulfiram/Antabuse (adverse reaction with alcohol).", "MAT is tested on the ASWB exam as evidence-based substance abuse treatment.", "MAT is most effective combined with counseling. It normalizes brain chemistry, not replaces one drug with another.", "Evaluate substance use severity, medical appropriateness, treatment history, and psychosocial stability.", "Coordinate with medical providers, provide counseling alongside medication, address stigma, and monitor adherence.", "Stigma against MAT prevents clients from accessing effective treatment.", ["MAT combines medication with counseling", "Methadone is full agonist; buprenorphine is partial agonist; naltrexone is antagonist", "MAT reduces mortality, relapse, and criminal behavior", "MAT normalizes brain chemistry, not replaces one drug with another"], ["Viewing MAT as replacing one addiction with another", "Not understanding differences between MAT medications", "Failing to integrate counseling with medication"], [{question: "What is the difference between methadone and buprenorphine?", answer: "Methadone is a full opioid agonist dispensed at licensed clinics. Buprenorphine is a partial agonist that can be prescribed by certified providers in office-based settings."}, {question: "Is MAT just replacing one drug with another?", answer: "No. MAT medications normalize brain chemistry disrupted by addiction, reduce cravings, and prevent withdrawal, enabling recovery when combined with counseling."}]),

  e("relapse-prevention", "Relapse Prevention", "Substance Abuse", "Relapse Prevention | ASWB Guide", "Learn about relapse prevention strategies for the ASWB exam.", ["relapse prevention", "Marlatt", "triggers", "coping skills", "ASWB"], "Relapse prevention (Marlatt) is a cognitive-behavioral approach to maintaining behavior change. It recognizes relapse as a process, not an event.", "Marlatt's model: high-risk situations lead to decreased self-efficacy and coping failures, potentially resulting in a lapse then relapse. The abstinence violation effect (AVE) occurs when guilt after a lapse escalates to full relapse. RP teaches that a lapse need not become a relapse.", "Relapse prevention is tested on the ASWB exam in the maintenance stage of change.", "Warning signs: returning to old networks, romanticizing past use, increased stress, isolation, neglecting self-care.", "Identify high-risk situations, triggers, coping skills, support systems, and past relapse patterns.", "Identify high-risk situations, develop coping skills, manage cravings (urge surfing), build recovery lifestyle, create emergency plans.", "The abstinence violation effect can escalate a lapse to full relapse.", ["Relapse is a process, not a single event", "A lapse does not have to become a full relapse", "The abstinence violation effect can escalate lapse to relapse", "Relapse prevention is cognitive-behavioral"], ["Viewing relapse as failure rather than learning opportunity", "Not distinguishing lapse from full relapse", "Failing to plan for high-risk situations"], [{question: "What is the abstinence violation effect?", answer: "Guilt and hopelessness after a lapse that can escalate a single use episode into a full relapse. RP teaches that a lapse is a learning opportunity."}, {question: "What is urge surfing?", answer: "A mindfulness technique where the individual observes and rides out a craving without acting on it, recognizing that cravings peak and pass."}]),

  // ===== CRISIS INTERVENTION =====
  e("suicide-risk-assessment", "Suicide Risk Assessment", "Crisis Intervention", "Suicide Risk Assessment | ASWB Exam Guide", "Learn about suicide risk assessment, protective factors, and intervention for the ASWB exam.", ["suicide", "risk assessment", "safety planning", "C-SSRS", "ASWB"], "Suicide risk assessment is a critical clinical skill. Assessment involves evaluating risk factors, protective factors, warning signs, and current suicidal ideation, intent, plan, and means.", "Risk factors: previous attempts (strongest predictor), mental illness, substance use, family history, access to lethal means, recent loss, isolation, chronic pain, hopelessness. Protective factors: social connectedness, reasons for living, religious beliefs, children in home. C-SSRS is a widely used tool.", "Suicide assessment is one of the most frequently tested topics on the ASWB exam.", "Warning signs: talking about wanting to die, hopelessness, feeling like a burden, increased substance use, withdrawing, giving away possessions, dramatic mood changes.", "Directly ask about suicidal ideation. Assess ideation, intent, plan, means, and timeline. Evaluate risk and protective factors.", "Safety planning (not no-suicide contracts), means restriction, crisis resources, increased monitoring, psychiatric evaluation, potential hospitalization.", "No-suicide contracts are not evidence-based and should not replace comprehensive safety planning.", ["Previous attempt is the strongest predictor", "Asking about suicide does not increase risk", "Safety planning is evidence-based; no-suicide contracts are not", "Means restriction saves lives"], ["Using no-suicide contracts instead of safety planning", "Being afraid to ask directly about suicidal ideation", "Not assessing for access to lethal means"], [{question: "Does asking about suicide increase risk?", answer: "No. Research consistently shows that asking about suicidal ideation does not increase risk and is essential for proper assessment."}, {question: "What is the strongest predictor of future suicide?", answer: "A previous suicide attempt is the single strongest predictor of future suicide."}]),

  e("disaster-mental-health", "Disaster Mental Health", "Crisis Intervention", "Disaster Mental Health | ASWB Guide", "Learn about disaster mental health response and psychological first aid for the ASWB exam.", ["disaster mental health", "psychological first aid", "PFA", "crisis response", "ASWB"], "Disaster mental health involves providing psychological support during and after disasters. Social workers provide PFA, crisis counseling, and ongoing services.", "Psychological First Aid (PFA) is the evidence-informed early intervention framework. PFA principles: contact, safety, stabilization, information, practical assistance, social support, coping information, and service linkage. PFA is NOT CISD. Critical incident stress debriefing has been found potentially harmful.", "Disaster mental health and PFA are tested on the ASWB exam.", "Normal stress reactions: shock, disbelief, anxiety, sleep disruption, irritability, difficulty concentrating. Most people are resilient.", "Screen for acute stress, identify higher-risk individuals, assess basic needs (safety, shelter, food, family reunification).", "PFA focuses on immediate needs, comfort, stabilization, and connecting with resources. Longer-term PTSD treatment as needed.", "CISD (forcing immediate trauma processing) can be harmful. Not all survivors need mental health services.", ["PFA is recommended over CISD", "Most disaster survivors are resilient", "Meet basic needs before psychological needs", "CISD has been found potentially harmful"], ["Recommending CISD instead of PFA", "Assuming all survivors need treatment", "Not prioritizing basic needs in disaster response"], [{question: "What is PFA?", answer: "Psychological First Aid is an evidence-informed early intervention for disaster survivors focusing on contact, safety, stabilization, and connection to resources."}, {question: "Is CISD still recommended?", answer: "No. Critical Incident Stress Debriefing has been found potentially harmful. PFA is now the recommended approach."}]),

  e("crisis-intervention-models", "Crisis Intervention Models", "Crisis Intervention", "Crisis Intervention Models | ASWB Guide", "Learn about crisis intervention models and techniques for the ASWB exam.", ["crisis intervention", "ABC model", "Roberts model", "crisis theory", "ASWB"], "Crisis intervention is a short-term, focused approach to help individuals in acute psychological crisis return to pre-crisis functioning.", "Models: ABC Model (A=Achieving contact, B=Boiling down the problem, C=Coping). Roberts Seven-Stage Model (assessment, rapport, identify problems, deal with feelings, generate alternatives, action plan, follow-up). Caplan: crisis occurs when usual coping is overwhelmed. Crisis is time-limited (4-6 weeks).", "Crisis intervention is tested on the ASWB exam.", "Crisis presents as emotional disequilibrium, cognitive disruption, behavioral disorganization, and impaired functioning.", "Rapid assessment of safety, lethality, coping resources, support systems, and precipitating event.", "Establish rapport, ensure safety, provide emotional support, identify needs, develop action plan, mobilize resources, arrange follow-up.", "Failure to assess safety and lethality first can lead to tragic outcomes.", ["Crisis is time-limited (4-6 weeks)", "Safety assessment comes first", "Crisis intervention restores pre-crisis functioning", "Crisis occurs when coping mechanisms are overwhelmed"], ["Not assessing for safety first", "Attempting long-term therapy during acute crisis", "Not developing a concrete action plan"], [{question: "What is the ABC model?", answer: "A=Achieving contact and rapport, B=Boiling down the problem to key issues, C=Coping by developing and implementing a plan."}, {question: "How long does a crisis typically last?", answer: "Crises are time-limited, typically resolving within 4-6 weeks. Crisis intervention aims to restore pre-crisis functioning during this window."}]),

  e("trauma-informed-care", "Trauma-Informed Care", "Crisis Intervention", "Trauma-Informed Care | ASWB Guide", "Learn about TIC principles and implementation for the ASWB exam.", ["trauma-informed care", "TIC", "SAMHSA", "ACEs", "ASWB"], "Trauma-informed care (TIC) is an organizational framework recognizing the widespread impact of trauma and integrating trauma knowledge into all service delivery.", "SAMHSA four Rs: Realize widespread impact, Recognize signs, Respond by integrating knowledge, Resist re-traumatization. Six principles: safety, trustworthiness/transparency, peer support, collaboration, empowerment/voice/choice, cultural/historical/gender issues. ACEs research demonstrated dose-response between childhood trauma and adult health outcomes.", "TIC is tested on the ASWB exam.", "Trauma responses: hypervigilance, avoidance, emotional dysregulation, dissociation, difficulty trusting, somatic complaints.", "Screen for trauma history using validated tools. Assess impact on functioning. Create safety.", "Universal trauma precautions, staff training, safe environments, avoid re-traumatization, offer choice, evidence-based trauma treatment.", "Mandating detailed trauma disclosure or confrontational approaches can re-traumatize clients.", ["SAMHSA four Rs: realize, recognize, respond, resist", "ACEs show dose-response relationship with adult outcomes", "TIC is an organizational framework, not a specific treatment", "Six principles include safety, trustworthiness, empowerment"], ["Confusing TIC (framework) with trauma treatment (clinical)", "Not recognizing how practices can re-traumatize", "Not understanding ACEs research"], [{question: "What is TIC?", answer: "An organizational framework that recognizes trauma's impact and integrates trauma knowledge into all policies, procedures, and practices to avoid re-traumatization."}, {question: "What are ACEs?", answer: "Adverse Childhood Experiences. Research shows a dose-response relationship between childhood trauma and adult health and social problems."}]),

  // ===== COMMUNITY PRACTICE =====
  e("needs-assessment", "Community Needs Assessment", "Community Practice", "Community Needs Assessment | ASWB Guide", "Learn about community needs assessment methods for the ASWB exam.", ["needs assessment", "community assessment", "program planning", "ASWB"], "Community needs assessment systematically identifies and analyzes community needs, resources, and gaps to inform program planning.", "Methods: surveys, focus groups, key informant interviews, community forums, existing data analysis, asset mapping, and windshield surveys. Mixed methods provide the most comprehensive picture.", "Needs assessment is tested on the ASWB exam in community practice and program development.", "Effective assessment involves community participation, cultural sensitivity, and attention to power dynamics.", "Examine demographics, health indicators, social indicators, existing services, gaps, barriers, and community assets.", "Results inform program planning, grant writing, resource allocation, and advocacy. Share findings with the community.", "Assessment without community participation produces biased results.", ["Community participation is essential", "Mixed methods provide comprehensive data", "Asset mapping identifies strengths alongside needs", "Share findings with the community"], ["Conducting assessment without community participation", "Focusing only on needs without identifying assets", "Not sharing findings with the community"], [{question: "What is asset mapping?", answer: "A community assessment technique that identifies and documents community strengths, resources, and capacities alongside needs and gaps."}, {question: "Why is community participation important in needs assessment?", answer: "It ensures findings reflect actual community priorities, reduces bias, builds community buy-in, and enhances the validity and usefulness of results."}]),

  e("grant-writing", "Grant Writing for Social Workers", "Community Practice", "Grant Writing in Social Work | ASWB Guide", "Learn about grant writing fundamentals for social work for the ASWB exam.", ["grant writing", "funding", "proposal", "SMART objectives", "ASWB"], "Grant writing enables programs and services to secure funding from government agencies, foundations, and other sources.", "Key components: needs statement (data-driven), program description (theory of change), evaluation plan (process and outcome measures), budget (detailed, justified), organizational capacity, and sustainability plan. SMART objectives: Specific, Measurable, Achievable, Relevant, Time-bound.", "Grant writing fundamentals are tested on the ASWB exam in program development contexts.", "Effective grants connect needs assessment data to proposed interventions with clear logic models.", "Evaluate organizational capacity, alignment with funder priorities, and available matching resources.", "Clear needs statement, theory of change, SMART objectives, evaluation plan, and detailed budget.", "Vague objectives and lack of evaluation plans are common reasons for rejection.", ["SMART objectives: Specific, Measurable, Achievable, Relevant, Time-bound", "Needs statements should be data-driven", "Evaluation plans must include process and outcome measures", "Logic models connect inputs to outcomes"], ["Writing vague objectives without measurable outcomes", "Not connecting needs to proposed intervention", "Omitting evaluation and sustainability plans"], [{question: "What are SMART objectives?", answer: "Objectives that are Specific, Measurable, Achievable, Relevant, and Time-bound."}, {question: "What is a logic model?", answer: "A visual representation connecting program inputs, activities, outputs, outcomes, and impact to show how the program is expected to work."}]),

  e("ecological-systems-theory", "Ecological Systems Theory", "Community Practice", "Ecological Systems Theory | ASWB Guide", "Learn about Bronfenbrenner's ecological systems theory for the ASWB exam.", ["ecological systems", "Bronfenbrenner", "person-in-environment", "ASWB"], "Ecological systems theory (Bronfenbrenner) examines how individuals interact with multiple environmental systems.", "Five systems: Microsystem (family, school), Mesosystem (interactions between microsystems), Exosystem (indirect influences like parent workplace), Macrosystem (culture, laws), Chronosystem (changes over time).", "Central to social work and frequently tested on the ASWB exam.", "Problems in one system level affect all other levels.", "Ecomap and genogram are key assessment tools.", "Interventions may target any level: individual therapy, family mediation, community development, or policy advocacy.", "Focusing exclusively on individual pathology without environmental factors is incomplete.", ["Person-in-environment is social work's signature perspective", "Five systems: micro, meso, exo, macro, chrono", "Ecomap visualizes client-environment relationships", "Problems in one level affect all others"], ["Confusing the five system levels", "Not considering environmental factors", "Focusing solely on individual pathology"], [{question: "What are the five systems?", answer: "Microsystem (immediate), Mesosystem (interactions between microsystems), Exosystem (indirect), Macrosystem (culture/society), Chronosystem (time/change)."}, {question: "What is an ecomap?", answer: "A visual tool mapping the client's relationships with people and systems, showing strong, weak, or stressful connections."}]),

  e("school-social-work", "School Social Work", "Community Practice", "School Social Work | ASWB Guide", "Learn about school social work practice and legal frameworks for the ASWB exam.", ["school social work", "IEP", "IDEA", "Section 504", "FERPA", "ASWB"], "School social workers provide mental health services, crisis intervention, case management, and advocacy in educational settings.", "Federal legislation: IDEA (special education, IEPs), Section 504 (accommodations), FERPA (educational record confidentiality). School social workers participate in IEP teams, conduct social histories, provide counseling.", "School social work is tested in community practice and child services contexts.", "Students may present with behavioral challenges, academic difficulties, anxiety, trauma, bullying, and family crises.", "Social-developmental histories, behavioral observations, mental health screening. Multi-tiered systems of support (MTSS).", "Individual/group counseling, crisis intervention, parent education, teacher consultation. Tier 1 (universal), Tier 2 (targeted), Tier 3 (intensive).", "FERPA, not HIPAA, governs school confidentiality.", ["IDEA provides IEPs; Section 504 provides accommodations", "FERPA governs school confidentiality, not HIPAA", "School social workers bridge home, school, and community", "MTSS provides tiered interventions"], ["Confusing IDEA with Section 504", "Applying HIPAA instead of FERPA", "Not understanding the IEP team role"], [{question: "What is the difference between IDEA and Section 504?", answer: "IDEA provides special education through IEPs. Section 504 provides accommodations for students with disabilities who may not qualify for special education."}, {question: "Does HIPAA apply in schools?", answer: "No. FERPA (Family Educational Rights and Privacy Act) governs educational record confidentiality in schools, not HIPAA."}]),

  e("case-management-social-work", "Case Management", "Community Practice", "Case Management in Social Work | ASWB Guide", "Learn about case management models and functions for the ASWB exam.", ["case management", "service coordination", "resource linkage", "ASWB"], "Case management is a collaborative process of assessment, planning, facilitation, coordination, and advocacy to meet comprehensive needs.", "Models: broker model (linking to services), clinical model (clinical services + coordination), strengths-based model (building on capacities), intensive model (complex needs, small caseloads). Core functions: assessment, planning, linkage, monitoring, advocacy.", "Case management is tested on the ASWB exam in community practice and service delivery.", "Clients typically have complex, multiple needs spanning health, housing, employment, and social support.", "Comprehensive evaluation of needs, strengths, resources, barriers, and goals across life domains.", "Assessment, planning, linkage, monitoring, and advocacy. Requires knowledge of community resources.", "Inadequate coordination leads to fragmentation. Insufficient monitoring means clients fall through cracks.", ["Assessment, planning, linkage, monitoring, and advocacy are core functions", "Strengths-based model builds on client capacities", "Advocacy is core, not just referral", "Know community resources and navigate systems"], ["Limiting case management to referral without follow-up", "Not monitoring service delivery", "Confusing case management models"], [{question: "What are the core functions of case management?", answer: "Assessment, planning, linkage (connecting to services), monitoring (tracking delivery), and advocacy (intervening when systems fail)."}, {question: "What is the broker model?", answer: "The simplest case management approach focusing on linking clients to existing services. May be insufficient for clients with complex needs."}]),

  // ===== CULTURAL COMPETENCE =====
  e("immigration-and-social-work", "Immigration and Social Work", "Cultural Competence", "Immigration in Social Work | ASWB Guide", "Learn about immigration-related issues and social work with immigrant populations for the ASWB exam.", ["immigration", "refugees", "asylum", "cultural competence", "ASWB"], "Social workers serve immigrant and refugee populations across all settings. Understanding immigration categories, unique stressors, and culturally responsive practice is essential.", "Categories: citizens, permanent residents, refugees (admitted from abroad), asylees (apply within U.S.), DACA recipients, temporary visa holders, undocumented. Different eligibility for benefits. Refugees eligible for most federal benefits; undocumented generally ineligible except emergency Medicaid and public education.", "Immigration is tested on the ASWB exam in diversity and cultural competence contexts.", "Immigrant clients may experience acculturation stress, language barriers, fear of deportation, family separation, trauma, discrimination, and loss of social status.", "Include immigration status (sensitively), acculturation level, language needs, trauma history, support systems, and barriers to services.", "Culturally responsive services, language access, trauma-informed care, legal referrals, benefits assistance, family support.", "Reporting immigration status violates ethical obligations unless legally required.", ["Each status has different benefit eligibility", "Refugees eligible for most federal benefits; undocumented generally not", "Do not report immigration status unless legally required", "Acculturation affects family dynamics across generations"], ["Assuming all immigrants have the same experiences", "Asking about status without building trust", "Not providing interpreter services"], [{question: "What is the difference between a refugee and an asylee?", answer: "Both face persecution, but refugees apply from abroad and are admitted before arrival. Asylees are already in the U.S. when they apply for protection."}, {question: "What benefits are undocumented immigrants eligible for?", answer: "Generally limited to emergency Medicaid and public education (K-12). Eligibility varies by state."}]),

  e("social-work-with-lgbtq", "Social Work with LGBTQ+ Populations", "Cultural Competence", "LGBTQ+ Social Work Practice | ASWB Guide", "Learn about affirming practice with LGBTQ+ populations for the ASWB exam.", ["LGBTQ", "sexual orientation", "gender identity", "affirmative practice", "ASWB"], "Affirming practice involves understanding unique experiences, addressing discrimination and minority stress, and providing culturally responsive services to LGBTQ+ communities.", "Minority stress theory (Meyer): chronic stress from stigma and discrimination. Coming out is a process, not an event. NASW affirms conversion therapy is harmful and unethical. Gender identity is distinct from sexual orientation. Use chosen names and pronouns.", "LGBTQ+ content is tested on the ASWB exam in diversity, ethics, and human development.", "LGBTQ+ individuals may experience elevated depression, anxiety, suicidality, and substance use, attributed to minority stress rather than identity itself.", "Assess identity development, discrimination experiences, family acceptance, support systems, and minority stress impact.", "Affirming interventions address stigma, support identity development, strengthen supports, and connect with LGBTQ+-specific resources.", "Conversion therapy is harmful and unethical. Failure to use affirming language damages the alliance.", ["Conversion therapy is harmful and unethical", "Gender identity is distinct from sexual orientation", "Use chosen names and pronouns", "Elevated risks are attributed to minority stress, not identity"], ["Conflating sexual orientation with gender identity", "Viewing LGBTQ+ identity as pathological", "Failing to use affirming language"], [{question: "What is minority stress theory?", answer: "Meyer's theory that LGBTQ+ individuals experience chronic stress from stigma, prejudice, and discrimination, contributing to higher rates of mental health problems."}, {question: "Is conversion therapy ethical?", answer: "No. NASW has clear policy that conversion therapy is harmful, ineffective, and unethical."}]),

  e("disability-and-social-work", "Disability and Social Work", "Cultural Competence", "Disability in Social Work | ASWB Guide", "Learn about disability perspectives and the ADA for the ASWB exam.", ["disability", "ADA", "social model", "ASWB"], "Social workers must understand disability models, the ADA, and language preferences for people with disabilities.", "Models: medical (disability as pathology, criticized), social (disability from societal barriers), biopsychosocial (WHO ICF). ADA (1990, amended 2008) prohibits discrimination and requires reasonable accommodations.", "Disability is tested on the ASWB exam in diversity and policy contexts.", "People with disabilities face physical, attitudinal, communication, and systemic barriers.", "Identify barriers and strengths, evaluate environmental impact, use preferred language.", "Advocacy for accessibility, empowerment approaches, independent living supports, assistive technology, policy advocacy.", "Applying only the medical model ignores environmental barriers.", ["Social model: disability results from societal barriers", "ADA requires reasonable accommodations", "Use client-preferred language", "Address individual needs and systemic barriers"], ["Applying only the medical model", "Using outdated language", "Assuming people with disabilities cannot make decisions"], [{question: "What is the social model of disability?", answer: "Disability results from societal barriers and attitudes rather than from the impairment itself."}, {question: "What does the ADA require?", answer: "The ADA prohibits discrimination based on disability and requires reasonable accommodations in employment, public services, and public accommodations."}]),

  // ===== CLINICAL ASSESSMENT =====
  e("dsm-5-diagnostic-system", "DSM-5 Diagnostic System", "Clinical Assessment", "DSM-5 in Social Work | ASWB Guide", "Learn about the DSM-5 diagnostic system for the ASWB exam.", ["DSM-5", "diagnosis", "mental disorders", "ASWB"], "The DSM-5 is the standard classification system for mental disorders in the U.S., used for diagnosis, treatment planning, and reimbursement.", "DSM-5 (2013) eliminated the multiaxial system, replaced GAF with WHODAS 2.0, created new categories (Trauma- and Stressor-Related Disorders), subsumed Asperger's under ASD. DSM-5-TR (2022) added Prolonged Grief Disorder.", "DSM-5 is essential ASWB clinical exam knowledge.", "Major chapters: Neurodevelopmental, Schizophrenia Spectrum, Bipolar, Depressive, Anxiety, OCD, Trauma/Stressor-Related, Substance-Related, Personality Disorders.", "Comprehensive assessment through interviews, observation, collateral contacts, and screening tools. Differential diagnosis.", "Use diagnoses for treatment planning, communication, and insurance. Complement with person-in-environment perspective.", "Over-reliance on diagnosis can pathologize normal responses. Cultural bias can lead to misdiagnosis.", ["DSM-5 eliminated the multiaxial system", "GAF replaced by WHODAS 2.0", "Asperger's now part of ASD", "DSM-5-TR added Prolonged Grief Disorder"], ["Not knowing DSM-IV to DSM-5 changes", "Confusing multiaxial system with DSM-5", "Not considering cultural factors"], [{question: "What changed from DSM-IV to DSM-5?", answer: "Eliminated multiaxial system, replaced GAF with WHODAS 2.0, reorganized chapters, created Trauma- and Stressor-Related Disorders category, and subsumed Asperger's under ASD."}, {question: "What is Prolonged Grief Disorder?", answer: "Added in DSM-5-TR (2022), it describes intense grief lasting at least 12 months (6 months in children) that is disproportionate to cultural norms and causes significant impairment."}]),

  e("mental-status-examination", "Mental Status Examination", "Clinical Assessment", "Mental Status Examination | ASWB Guide", "Learn about MSE components for the ASWB exam.", ["MSE", "mental status exam", "clinical assessment", "ASWB"], "The MSE is a structured assessment of current mental functioning through observation and clinical interview.", "Components: Appearance, Behavior, Speech, Mood (client subjective), Affect (clinician observation), Thought Process (logical/circumstantial/tangential), Thought Content (SI/HI, delusions), Perception (hallucinations), Cognition (orientation, memory), Insight and Judgment.", "MSE is essential ASWB knowledge. Key distinctions are commonly tested.", "Normal: appropriate grooming, cooperative, normal speech, euthymic mood, congruent affect, logical thought process, no content abnormalities, intact cognition.", "Systematic observation and targeted questioning during assessment interview.", "Document in standardized format and integrate with other assessment data.", "Incomplete documentation can miss diagnoses. Not assessing for SI can be life-threatening.", ["Mood is subjective (client); affect is objective (clinician)", "Circumstantial returns to the point; tangential never returns", "Flat = no expression; blunted = reduced; labile = rapid shifts", "Always assess for SI/HI"], ["Confusing mood with affect", "Confusing circumstantial with tangential", "Confusing blunted with flat affect"], [{question: "What is the difference between mood and affect?", answer: "Mood is the client's subjective emotional state (what they report). Affect is the clinician's objective observation of emotional expression."}, {question: "What is the difference between circumstantial and tangential thinking?", answer: "Circumstantial: excessive detail but eventually reaches the point. Tangential: goes off-topic and never returns to the point."}]),

  e("risk-assessment-tools", "Risk Assessment Tools", "Clinical Assessment", "Risk Assessment Tools | ASWB Guide", "Learn about standardized risk assessment instruments for the ASWB exam.", ["risk assessment", "PHQ-9", "GAD-7", "AUDIT", "ASWB"], "Standardized instruments that help systematically evaluate client risk across domains.", "Common tools: PHQ-9 (depression, 0-27), GAD-7 (anxiety, 0-21), AUDIT (alcohol, 10 items), DAST (drugs), C-SSRS (suicide), PCL-5 (PTSD), Danger Assessment (DV lethality).", "Risk assessment tools are tested on the ASWB exam.", "Results indicate severity and guide decisions. Positive screens require follow-up.", "Select tools based on clinical question, population, and setting. Use culturally appropriate tools.", "Inform treatment planning, level of care, safety planning, and referrals. Supplement, not replace, judgment.", "Over-reliance without clinical judgment misses nuanced presentations.", ["Tools supplement, not replace, clinical judgment", "PHQ-9 for depression; GAD-7 for anxiety; AUDIT for alcohol", "Positive screens require follow-up", "Use validated tools for the population"], ["Using screening tools as diagnostic instruments", "Not following up on positive screens", "Using unvalidated tools"], [{question: "What does the PHQ-9 screen for?", answer: "Depression. It has 9 items with scores from 0-27, with established cutoffs for mild, moderate, moderately severe, and severe depression."}, {question: "Do screening tools replace clinical judgment?", answer: "No. They supplement clinical judgment by providing standardized data. A positive screen requires follow-up clinical assessment."}]),

  e("strengths-based-assessment", "Strengths-Based Assessment", "Clinical Assessment", "Strengths-Based Assessment | ASWB Guide", "Learn about strengths-based assessment for the ASWB exam.", ["strengths-based", "strengths perspective", "Saleebey", "ASWB"], "Identifies client strengths, resources, and capacities alongside challenges. Rooted in the strengths perspective (Dennis Saleebey).", "Principles: everyone has strengths, adversity can be a source of growth, upper limits of change are unknown, collaboration is essential, every environment has resources.", "Central to social work and tested on the ASWB exam.", "Strengths include personal attributes, social resources, cultural resources, and environmental resources.", "Explore what works, past successes, coping strategies, support networks, values, and aspirations.", "Build on strengths to address challenges. Collaborative goals.", "Focusing exclusively on strengths while ignoring risks compromises safety.", ["Does not ignore problems, addresses them while recognizing capacities", "All people have strengths", "Document strengths alongside challenges", "Aligns with empowerment and self-determination"], ["Ignoring genuine risks while focusing on strengths", "Treating strengths-based as incompatible with clinical assessment", "Failing to document strengths"], [{question: "What is the strengths perspective?", answer: "A framework emphasizing client strengths, resources, and resilience alongside challenges, developed by Dennis Saleebey."}, {question: "Does strengths-based practice ignore problems?", answer: "No. It addresses problems while simultaneously identifying and building on client strengths and capacities."}]),

  // ===== PSYCHOTHERAPY APPROACHES =====
  e("cognitive-behavioral-therapy-sw", "Cognitive Behavioral Therapy in Social Work", "Psychotherapy Approaches", "CBT in Social Work | ASWB Guide", "Learn about CBT principles and techniques for the ASWB exam.", ["CBT", "Aaron Beck", "cognitive distortions", "ASWB"], "CBT (Aaron Beck) is an evidence-based, structured, time-limited therapy addressing the relationship between thoughts, feelings, and behaviors.", "The cognitive model: situations activate automatic thoughts, which influence emotions and behaviors. Cognitive distortions: all-or-nothing thinking, catastrophizing, mind reading, overgeneralization, personalization, mental filtering.", "CBT is one of the most frequently tested approaches on the ASWB exam.", "Effective for depression, anxiety, PTSD, eating disorders. Structured with agenda-setting and homework.", "Identify automatic thoughts, beliefs, behavioral patterns, and triggers. Thought records.", "Cognitive restructuring, behavioral activation, exposure therapy, relaxation, problem-solving. Homework is essential.", "May not suit severe cognitive impairments or acute crisis.", ["CBT addresses thoughts-feelings-behaviors", "Cognitive distortions maintain emotional distress", "Homework is essential", "Evidence-based for many conditions"], ["Not identifying cognitive distortions", "Confusing CBT with psychodynamic approaches", "Forgetting homework is integral"], [{question: "What is the cognitive model?", answer: "Situations activate automatic thoughts, which influence emotions and behaviors. Changing distorted thinking improves emotional and behavioral responses."}, {question: "What are cognitive distortions?", answer: "Systematic thinking errors including all-or-nothing thinking, catastrophizing, mind reading, overgeneralization, personalization, and mental filtering."}]),

  e("solution-focused-family-therapy", "Solution-Focused Family Therapy", "Family Systems", "Solution-Focused Family Therapy | ASWB Guide", "Learn about solution-focused techniques in family therapy for the ASWB exam.", ["solution-focused", "miracle question", "scaling questions", "ASWB"], "Applies SFBT principles to family systems, focusing on solutions and building on family strengths and past successes.", "Key techniques: miracle question, scaling questions (1-10), exception questions, compliments, and first session formula task. Not-knowing stance.", "Solution-focused approaches are tested on the ASWB exam.", "Families identify what is already working and build on existing solutions.", "Family goals, exceptions to the problem, existing solutions, and strengths.", "Goal-oriented, brief, collaborative. Small changes lead to larger shifts.", "Insufficient for active violence or severe mental illness.", ["Miracle question envisions life without the problem", "Exception questions identify problem-free times", "Brief and goal-oriented", "Not-knowing, curious stance"], ["Confusing with narrative therapy", "Not understanding miracle question", "Using when safety is compromised"], [{question: "What is the miracle question?", answer: "If a miracle happened tonight and the problem was solved, what would be different tomorrow? It helps families envision their preferred future."}, {question: "What are exception questions?", answer: "Questions identifying times when the problem is absent or less severe, revealing existing solutions to build upon."}]),

  e("structural-family-therapy", "Structural Family Therapy", "Family Systems", "Structural Family Therapy | ASWB Guide", "Learn about Minuchin's structural family therapy for the ASWB exam.", ["structural family therapy", "Minuchin", "boundaries", "subsystems", "ASWB"], "Structural family therapy (Minuchin) focuses on family structure and the invisible rules organizing family interactions.", "Key concepts: subsystems (spousal, parental, sibling), boundaries (clear, rigid, diffuse/enmeshed), hierarchy, triangulation, coalitions. Techniques: joining, enactment, boundary making, unbalancing, restructuring.", "Tested on the ASWB exam.", "Dysfunctional structures: enmeshment, disengagement, inappropriate hierarchy, cross-generational coalitions, triangulation.", "Map family structure through observation of interactions, identifying subsystems, boundaries, hierarchy.", "Joining, enactment, boundary making, unbalancing, and restructuring.", "Imposing cultural norms about family structure without sensitivity damages the alliance.", ["Boundaries: clear, rigid, or diffuse/enmeshed", "Triangulation draws a third into dyadic conflict", "Minuchin developed structural family therapy", "Joining is the technique for engaging with the family"], ["Confusing enmeshment with disengagement", "Not understanding triangulation", "Confusing structural with strategic family therapy"], [{question: "What is enmeshment?", answer: "Diffuse boundaries where family members are overly involved in each other's lives, limiting individual autonomy."}, {question: "What is joining?", answer: "The therapist's technique of building an alliance with the family by adapting to their communication style and demonstrating respect."}]),

  // ===== ETHICS & LEGAL ISSUES =====
  e("informed-consent-social-work", "Informed Consent", "Ethics & Legal Issues", "Informed Consent | ASWB Guide", "Learn about informed consent requirements for the ASWB exam.", ["informed consent", "client rights", "NASW", "ASWB"], "Informed consent is a foundational ethical and legal requirement. NASW Code of Ethics Section 1.03 requires valid informed consent for services.", "Three elements: Capacity (ability to understand and decide), Information (services, risks, benefits, alternatives, confidentiality limits), Voluntariness (freedom from coercion). Special considerations for minors, diminished capacity, and involuntary clients.", "One of the most frequently tested ethical topics on the ASWB exam.", "Key situations: beginning of treatment, treatment changes, releasing information, recording sessions, research.", "Evaluate ability to understand, appreciate, reason, and communicate a choice.", "Obtain at outset and revisit throughout. Document consent.", "Services without consent constitute ethical violations. Not discussing confidentiality limits before disclosure is a common error.", ["Ongoing process, not one-time event", "Three elements: capacity, information, voluntariness", "Discuss confidentiality limits before disclosure", "Special procedures for minors and diminished capacity"], ["Treating consent as one-time form signing", "Failing to discuss confidentiality limits", "Not reassessing when treatment changes"], [{question: "What are the three elements of informed consent?", answer: "Capacity (ability to understand), information (adequate disclosure), and voluntariness (freedom from coercion)."}, {question: "Is informed consent a one-time event?", answer: "No. It is an ongoing process revisited throughout the professional relationship."}]),

  e("duty-to-warn-and-protect", "Duty to Warn and Protect", "Ethics & Legal Issues", "Duty to Warn and Protect | ASWB Guide", "Learn about the Tarasoff ruling and social work obligations for the ASWB exam.", ["duty to warn", "duty to protect", "Tarasoff", "ASWB"], "The duty to warn and protect requires action when a client presents a credible threat to an identifiable third party, stemming from Tarasoff v. Regents (1976).", "Tarasoff I (1974): duty to warn the victim. Tarasoff II (1976): expanded to duty to protect (warning, police notification, hospitalization, or other reasonable steps). State laws vary significantly.", "One of the most important and frequently tested topics on the ASWB exam.", "Triggered when: credible threat, identifiable victim, serious intent. Evaluate specificity, history of violence, access to means.", "Evaluate seriousness, capacity and intent, history, access to means, and victim identifiability.", "Warn victim, notify law enforcement, hospitalize, increase monitoring, or adjust treatment. Take least restrictive adequate action.", "Failure to act on a credible threat results in harm and liability. Breaching confidentiality without justification violates ethics.", ["Tarasoff established duty to protect identifiable victims", "Duty to protect is broader than duty to warn", "State laws vary in implementation", "Recognized exception to confidentiality"], ["Confusing duty to warn with duty to protect", "Not knowing the Tarasoff case", "Failing to act due to confidentiality concerns"], [{question: "What is the Tarasoff ruling?", answer: "Mental health professionals have a duty to protect identifiable potential victims when a client makes a credible threat of harm, creating a legal exception to confidentiality."}, {question: "What is the difference between duty to warn and duty to protect?", answer: "Duty to warn means telling the victim. Duty to protect is broader and includes warning, notifying police, hospitalization, or other protective steps."}]),

  e("social-work-supervision-models", "Social Work Supervision", "Ethics & Legal Issues", "Social Work Supervision | ASWB Guide", "Learn about supervision models and ethical obligations for the ASWB exam.", ["supervision", "clinical supervision", "Kadushin", "ASWB"], "Supervision is a professional relationship providing guidance, support, and oversight to less experienced practitioners.", "Kadushin's three functions: Administrative (compliance, workload, evaluation), Educational (clinical knowledge, skills), Supportive (managing stress, vicarious trauma). Supervisory models include developmental, competency-based, and reflective models.", "Supervision is tested in professional development and ethics contexts on the ASWB exam.", "Effective supervision: regular meetings, case review, skill development, attention to growth and well-being.", "Evaluate supervisee competence, learning needs, ethical concerns, and burnout/vicarious trauma signs.", "Case consultation, modeling, reflective practice, performance evaluation, ensuring ethical practice. Documentation required for licensure.", "Inadequate supervision leads to ethical violations and client harm. Supervisors bear vicarious liability.", ["Kadushin's three functions: administrative, educational, supportive", "Supervisors bear vicarious liability", "Supervision should not serve as therapy", "Documentation is required for licensure"], ["Confusing the three functions", "Not recognizing vicarious liability", "Blurring supervision and therapy boundaries"], [{question: "What are the three functions of supervision?", answer: "Administrative (organizational accountability), educational (developing skills), and supportive (managing emotional demands)."}, {question: "What is vicarious liability?", answer: "Supervisors are legally responsible for supervisee actions. If a supervisee causes harm through negligence, the supervisor may also be held liable."}]),

  // ===== HUMAN DEVELOPMENT =====
  e("kohlberg-moral-development", "Kohlberg's Moral Development", "Human Development", "Kohlberg's Moral Development | ASWB Guide", "Learn about Kohlberg's stages of moral development for the ASWB exam.", ["Kohlberg", "moral development", "moral reasoning", "ASWB"], "Kohlberg's theory describes moral reasoning evolving through three levels and six stages.", "Pre-conventional (Stages 1-2): self-interest. Conventional (Stages 3-4): social conformity. Post-conventional (Stages 5-6): abstract principles. Most adults at Stages 3-4. Gilligan critiqued gender bias, proposed ethic of care.", "Tested alongside other developmental theories on the ASWB exam.", "Children progress from pre-conventional to conventional. Some adults develop post-conventional reasoning.", "Evaluate moral reasoning through ethical dilemma discussions.", "Understanding reasoning level helps tailor interventions.", "Applying a single cultural framework without considering variations.", ["Pre-conventional=self-interest; conventional=conformity; post-conventional=principles", "Most adults at conventional level", "Gilligan critiqued gender bias, proposed ethic of care", "Linked to but not identical to cognitive development"], ["Confusing levels and stages", "Not knowing Gilligan's critique", "Expecting post-conventional reasoning from children"], [{question: "What are the three levels?", answer: "Pre-conventional (self-interest), Conventional (social conformity/law and order), Post-conventional (abstract ethical principles)."}, {question: "What is Gilligan's critique?", answer: "Kohlberg's theory is biased toward male justice reasoning. Gilligan proposed an ethic of care emphasizing relationships and responsibility."}]),

  e("adolescent-development", "Adolescent Development", "Human Development", "Adolescent Development | ASWB Guide", "Learn about adolescent development for the ASWB exam.", ["adolescent development", "identity formation", "puberty", "ASWB"], "Adolescence (ages 12-18) is characterized by profound physical, cognitive, emotional, and social changes.", "Physical: puberty, brain development (prefrontal cortex not fully developed until ~25). Cognitive: formal operational thinking (Piaget). Psychosocial: Identity vs. Role Confusion (Erikson), peer centrality. Social: peak peer influence, romantic relationships.", "Tested in human development and clinical contexts on the ASWB exam.", "Normal: mood variability, risk-taking, peer orientation, questioning authority. Red flags: persistent depression, self-harm, substance abuse, school failure.", "Developmentally informed assessment considering cognitive level, identity development, peer context, and family dynamics.", "MI, CBT adapted for adolescents, family therapy, group work, school-based interventions.", "Pathologizing normal behavior leads to unnecessary treatment.", ["Prefrontal cortex not fully developed until ~25", "Erikson's adolescent crisis: Identity vs. Role Confusion", "Peer influence peaks and is normal", "Risk-taking serves developmental purpose"], ["Pathologizing normal adolescent behavior", "Treating adolescents exactly like adults or children", "Not considering brain development"], [{question: "Why do adolescents take risks?", answer: "The prefrontal cortex (judgment/impulse control) is not fully developed until ~25, while the limbic system (emotion/reward) is highly active, combined with identity exploration and peer influence."}, {question: "What is Erikson's adolescent stage?", answer: "Identity vs. Role Confusion. Adolescents explore their sense of self. Successful resolution produces a coherent identity and the virtue of fidelity."}]),

  e("erikson-psychosocial-supplement", "Erikson's Psychosocial Stages (Detailed)", "Human Development", "Erikson's Psychosocial Development | ASWB Guide", "Learn about Erikson's eight stages of psychosocial development for the ASWB exam.", ["Erikson", "psychosocial development", "identity", "life stages", "ASWB"], "Erik Erikson proposed eight stages of psychosocial development spanning the entire lifespan, each with a central crisis.", "Eight stages: Trust vs. Mistrust (infancy/hope), Autonomy vs. Shame (toddler/will), Initiative vs. Guilt (preschool/purpose), Industry vs. Inferiority (school age/competence), Identity vs. Role Confusion (adolescence/fidelity), Intimacy vs. Isolation (young adult/love), Generativity vs. Stagnation (middle adult/care), Integrity vs. Despair (late adult/wisdom).", "Among the most frequently tested developmental theories on the ASWB exam.", "Each stage builds on resolution of the previous one. Successful resolution produces a specific virtue.", "Identify current stage and whether previous stages have been adequately resolved.", "Address unresolved developmental crises and support current stage tasks.", "Rigid application without cultural and individual variation.", ["Trust vs. Mistrust is the foundation", "Identity vs. Role Confusion is adolescent", "Generativity vs. Stagnation is middle adult", "Each stage builds on the previous"], ["Not knowing all eight stages in order", "Confusing which crisis belongs to which stage", "Not knowing corresponding virtues"], [{question: "What are the eight stages in order?", answer: "Trust vs. Mistrust, Autonomy vs. Shame/Doubt, Initiative vs. Guilt, Industry vs. Inferiority, Identity vs. Role Confusion, Intimacy vs. Isolation, Generativity vs. Stagnation, Integrity vs. Despair."}, {question: "What virtues correspond to each stage?", answer: "Hope, will, purpose, competence, fidelity, love, care, and wisdom (in order)."}]),

  e("piaget-cognitive-supplement", "Piaget's Cognitive Development (Detailed)", "Human Development", "Piaget's Cognitive Development | ASWB Guide", "Learn about Piaget's stages of cognitive development for the ASWB exam.", ["Piaget", "cognitive development", "sensorimotor", "formal operational", "ASWB"], "Jean Piaget described four stages of cognitive development that children progress through sequentially.", "Sensorimotor (0-2): learning through senses, object permanence. Preoperational (2-7): symbolic thinking, egocentrism, no conservation. Concrete Operational (7-11): logical thinking about concrete objects, conservation. Formal Operational (11+): abstract thinking, hypothetical reasoning.", "Frequently tested on the ASWB exam.", "Children progress sequentially; stages cannot be skipped but timing varies.", "Identify cognitive stage to guide communication and intervention.", "Match interventions to cognitive stage.", "Expecting abilities beyond cognitive stage causes frustration.", ["Sensorimotor: object permanence", "Preoperational: egocentrism, no conservation", "Concrete Operational: logical concrete thinking", "Formal Operational: abstract reasoning"], ["Confusing stages and characteristics", "Not knowing when object permanence develops", "Not understanding conservation"], [{question: "What is object permanence?", answer: "Understanding that objects continue to exist even when not visible, developing during the sensorimotor stage (around 8 months)."}, {question: "What is conservation?", answer: "Understanding that quantity remains the same despite changes in shape or arrangement, developing in the concrete operational stage."}]),

  e("maslow-hierarchy-supplement", "Maslow's Hierarchy of Needs (Detailed)", "Human Development", "Maslow's Hierarchy of Needs | ASWB Guide", "Learn about Maslow's hierarchy and its application to social work for the ASWB exam.", ["Maslow", "hierarchy of needs", "self-actualization", "ASWB"], "Maslow's hierarchy proposes that human needs are arranged hierarchically with basic survival needs at the base.", "Five levels: (1) Physiological (food, water, shelter), (2) Safety (security, stability), (3) Love/Belonging (relationships), (4) Esteem (self-respect, recognition), (5) Self-actualization (personal growth). Lower needs must be substantially met before higher needs motivate.", "Tested on the ASWB exam and directly applicable to intervention planning.", "A homeless client will not focus on self-actualization until basic needs are met.", "Assess which need level is most pressing and barriers to meeting needs.", "Address most pressing level first. Concrete services may precede therapy.", "Therapy when basic needs are unmet is often ineffective.", ["Basic needs must be addressed first", "Supports meeting clients where they are", "Concrete services may precede clinical work", "Self-actualization is at the top"], ["Not addressing basic needs before therapy", "Applying hierarchy too rigidly", "Ignoring cultural variations"], [{question: "What are the five levels?", answer: "Physiological, Safety, Love/Belonging, Esteem, and Self-actualization (from base to top)."}, {question: "How does this apply to social work?", answer: "Address basic needs (food, housing, safety) before expecting engagement in therapeutic work. Meet clients where they are."}]),

  // ===== POLICY & ADVOCACY =====
  e("legislative-advocacy", "Legislative Advocacy", "Policy & Advocacy", "Legislative Advocacy | ASWB Guide", "Learn about legislative advocacy strategies for the ASWB exam.", ["legislative advocacy", "lobbying", "policy change", "ASWB"], "Legislative advocacy is a core social work function mandated by the NASW Code of Ethics.", "Strategies: direct lobbying, grassroots organizing, coalition building, public education, voter registration, media advocacy. Understanding the legislative process is essential.", "Tested on the ASWB exam in policy practice and macro social work.", "Effective advocacy requires understanding the political process, building relationships, using data, and mobilizing stakeholders.", "Analyze proposals, identify stakeholders, evaluate feasibility, assess impacts on vulnerable populations.", "Build coalitions, develop policy briefs, provide testimony, mobilize constituents, engage media.", "Government employees may face lobbying restrictions.", ["Advocacy is a professional obligation under NASW", "Grassroots organizing mobilizes community members", "Coalition building strengthens advocacy", "Policy briefs provide data-driven summaries"], ["Not understanding the legislative process", "Failing to distinguish lobbying from education", "Not recognizing advocacy as core social work"], [{question: "Is advocacy required by the NASW Code of Ethics?", answer: "Yes. The Code of Ethics calls on social workers to engage in social and political action to promote social justice."}, {question: "What is a policy brief?", answer: "A concise document summarizing a policy issue, presenting evidence, and recommending action for decision-makers."}]),

  e("health-care-policy", "Health Care Policy", "Policy & Advocacy", "Health Care Policy | ASWB Guide", "Learn about major health care policies for the ASWB exam.", ["health care policy", "ACA", "Medicaid", "Medicare", "ASWB"], "Social workers must understand health care policies affecting client access to services.", "Medicare: federal, 65+ and disabled (Part A hospital, Part B outpatient, Part C Advantage, Part D drugs). Medicaid: joint federal-state, low-income. ACA: expanded Medicaid, created marketplaces, essential benefits, banned pre-existing condition exclusions. Mental Health Parity Act: equivalent coverage for mental health and substance use.", "Tested on the ASWB exam in social welfare policy.", "Access barriers: cost, geography, language, cultural factors, coverage gaps.", "Evaluate insurance status, barriers to care, health literacy, unmet needs.", "Insurance enrollment assistance, system navigation, care coordination, benefits education.", "Lack of insurance prevents access to needed services.", ["Medicare for 65+/disabled; Medicaid for low-income", "ACA expanded Medicaid and created marketplaces", "Mental Health Parity requires equivalent coverage", "Social workers help navigate complex systems"], ["Confusing Medicare with Medicaid", "Not knowing ACA provisions", "Not understanding Mental Health Parity"], [{question: "What is the difference between Medicare and Medicaid?", answer: "Medicare is federal health insurance for people 65+ and some disabled individuals. Medicaid is a joint federal-state program for low-income individuals."}, {question: "What is Mental Health Parity?", answer: "The Mental Health Parity and Addiction Equity Act requires health plans to provide equivalent coverage for mental health and substance use services as for medical/surgical services."}]),

  e("social-welfare-policy-history", "Social Welfare Policy History", "Policy & Advocacy", "Social Welfare Policy History | ASWB Guide", "Learn about U.S. social welfare policy history for the ASWB exam.", ["social welfare history", "New Deal", "settlement houses", "Jane Addams", "ASWB"], "Understanding social welfare history provides context for current practice and policy.", "Key eras: COS and Settlement Houses (1880s-1900s). Progressive Era: child labor laws. New Deal (1930s): Social Security Act of 1935. War on Poverty (1960s): Medicare, Medicaid, Head Start. 1996 Welfare Reform: TANF replaced AFDC with work requirements and time limits.", "Tested on the ASWB exam.", "Tension between individual and social responsibility has shaped U.S. policy throughout history.", "Current policy requires understanding historical context.", "Use historical knowledge to contextualize current debates and advocate effectively.", "Ahistorical analysis can repeat past mistakes.", ["Jane Addams founded Hull House", "Social Security Act of 1935 is the safety net foundation", "1996 reform replaced AFDC with TANF", "COS: individual reform; settlement houses: social reform"], ["Not knowing Jane Addams and Hull House", "Confusing COS with settlement houses", "Not knowing Social Security Act", "Confusing AFDC with TANF"], [{question: "Who founded Hull House?", answer: "Jane Addams founded Hull House in 1889 in Chicago, a settlement house providing services to immigrants and advocating for social reform."}, {question: "What did the 1996 welfare reform do?", answer: "Replaced Aid to Families with Dependent Children (AFDC) with Temporary Assistance for Needy Families (TANF), adding work requirements, time limits, and state block grants."}]),

  e("poverty-and-social-work", "Poverty and Social Work", "Policy & Advocacy", "Poverty in Social Work | ASWB Guide", "Learn about poverty theories and social work responses for the ASWB exam.", ["poverty", "economic inequality", "TANF", "ASWB"], "Poverty is central to social work practice and policy, addressed at micro, mezzo, and macro levels.", "Theories: individual/cultural (contested), structural (economic/social systems), intersectional (race, gender, disability). Federal poverty level (FPL) is official measure; supplemental poverty measure (SPM) accounts for costs and benefits.", "Tested on the ASWB exam.", "Poverty impacts health, education, housing, child development, and safety.", "Assess economic status, employment, housing, food security, healthcare access, and poverty's impact on presenting problem.", "Direct services, community development, and policy advocacy.", "Attributing poverty solely to individual factors ignores structural causes.", ["Structural theories attribute poverty to systems, not individuals", "Poverty disproportionately affects communities of color, women, children", "Address at micro, mezzo, and macro levels", "FPL likely understates actual poverty"], ["Attributing poverty solely to individual choices", "Not assessing poverty's impact on presenting problem", "Confusing FPL with actual need"], [{question: "What is structural poverty theory?", answer: "Poverty results from economic and social structures that create inequality, not from individual failings."}, {question: "What populations are disproportionately affected?", answer: "Communities of color, women (especially single mothers), children, people with disabilities, and immigrants."}]),

  // ===== RESEARCH METHODS =====
  e("program-evaluation", "Program Evaluation", "Research Methods", "Program Evaluation | ASWB Guide", "Learn about program evaluation methods for the ASWB exam.", ["program evaluation", "outcome evaluation", "logic model", "ASWB"], "Systematic assessment of program design, implementation, and outcomes to improve services and ensure accountability.", "Types: formative (improve during implementation), summative (judge after completion), process (how it operates), outcome (what it achieves). Logic models connect inputs, activities, outputs, outcomes, impact. RCTs strongest evidence; quasi-experimental more common.", "Tested on the ASWB exam in research and evidence-based practice.", "Requires clear objectives, appropriate design, valid measures, and stakeholder involvement.", "Clarify program theory, identify measurable outcomes, select design and measures.", "Implement plan, collect data, analyze, report findings, use for improvement.", "Poorly designed evaluation produces misleading results.", ["Process examines how; outcome examines what", "Logic models connect inputs to outcomes", "Formative improves; summative judges", "Stakeholder involvement improves quality"], ["Confusing formative with summative", "Not understanding logic models", "No measurable objectives"], [{question: "What is a logic model?", answer: "A visual representation connecting program inputs, activities, outputs, outcomes, and impact to show how the program works."}, {question: "What is the difference between formative and summative evaluation?", answer: "Formative evaluation improves programs during implementation. Summative evaluation judges effectiveness after completion."}]),

  e("qualitative-research-methods", "Qualitative Research Methods", "Research Methods", "Qualitative Research | ASWB Guide", "Learn about qualitative research methods in social work for the ASWB exam.", ["qualitative research", "ethnography", "grounded theory", "ASWB"], "Qualitative research uses non-numerical data to understand social phenomena in depth, valued for amplifying client voices.", "Approaches: ethnography (cultural immersion), grounded theory (theory from data), phenomenology (lived experience), case study, narrative. Data: interviews, focus groups, observation. Rigor: credibility, transferability, dependability, confirmability. Purposive sampling.", "Tested on the ASWB exam.", "Smaller samples than quantitative but deeper understanding.", "Select approach, develop interview guide, obtain IRB approval, plan data management.", "Coding, theme development, interpretation. Member checking validates findings.", "Cannot establish causation and not statistically generalizable.", ["Purposive sampling, not random", "Rigor: credibility, transferability, dependability, confirmability", "Member checking validates findings", "Grounded theory builds theory from data"], ["Confusing qualitative rigor with quantitative validity", "Not understanding differences between approaches", "Applying quantitative standards to qualitative"], [{question: "What is grounded theory?", answer: "A qualitative approach that builds theory from data rather than testing existing theory."}, {question: "What is member checking?", answer: "Sharing findings with participants to validate accuracy and credibility."}]),

  e("research-ethics", "Research Ethics", "Research Methods", "Research Ethics | ASWB Guide", "Learn about research ethics and IRB requirements for the ASWB exam.", ["research ethics", "IRB", "Belmont Report", "Tuskegee", "ASWB"], "Research ethics protect human subjects. Social workers must follow the Belmont Report and IRB requirements.", "Belmont Report (1979) three principles: Respect for Persons (informed consent, protect vulnerable), Beneficence (maximize benefit, minimize harm), Justice (fair distribution). Tuskegee study led to the Belmont Report. IRB review required for human subjects.", "Tested on the ASWB exam.", "Research consent requires disclosure of purpose, procedures, risks, benefits, alternatives, and right to withdraw.", "IRB evaluates risks, consent procedures, confidentiality protections, and vulnerable population protections.", "Obtain IRB approval, secure consent, protect confidentiality, minimize risks, ensure voluntary participation.", "Research without ethical oversight can cause serious harm.", ["Belmont Report: respect for persons, beneficence, justice", "Tuskegee led to modern research ethics", "IRB review required for human subjects", "Participants can withdraw without penalty"], ["Not knowing Belmont Report principles", "Not understanding IRB requirements", "Confusing research and clinical consent"], [{question: "What is the Belmont Report?", answer: "A 1979 document establishing three ethical principles for research with human subjects: Respect for Persons, Beneficence, and Justice."}, {question: "What was the Tuskegee study?", answer: "A notorious unethical study (1932-1972) that denied treatment to Black men with syphilis. It led to the Belmont Report and modern research ethics protections."}]),

  // ===== GROUP WORK =====
  e("group-dynamics", "Group Dynamics", "Group Work", "Group Dynamics | ASWB Guide", "Learn about group dynamics concepts for the ASWB exam.", ["group dynamics", "cohesion", "norms", "Yalom", "ASWB"], "Group dynamics refers to forces and processes within groups influencing member behavior and outcomes.", "Key concepts: cohesion, norms, roles (leader, mediator, scapegoat, monopolizer), subgroups, power dynamics, communication patterns, conflict. Yalom's therapeutic factors: universality, instillation of hope, altruism, catharsis, interpersonal learning, cohesiveness.", "Tested on the ASWB exam.", "Positive: cohesion, mutual aid. Negative: scapegoating, monopolizing, destructive subgroups.", "Observe interaction patterns, communication, roles, norms, and power dynamics.", "Address negative dynamics directly, promote cohesion, establish constructive norms, manage conflict.", "Unaddressed negative dynamics harm members and destroy group effectiveness.", ["Yalom's therapeutic factors include universality and cohesiveness", "Scapegoating targets one member", "Norms are established early and shape behavior", "Address negative dynamics directly"], ["Not recognizing group roles", "Not understanding Yalom's factors", "Allowing negative dynamics to continue"], [{question: "What are Yalom's therapeutic factors?", answer: "Forces within groups that promote healing, including universality, instillation of hope, altruism, catharsis, interpersonal learning, and group cohesiveness."}, {question: "What is scapegoating?", answer: "When the group directs blame, hostility, or frustration toward one member. The facilitator must address this directly."}]),

  e("tuckman-group-stages", "Tuckman's Stages of Group Development", "Group Work", "Tuckman's Group Stages | ASWB Guide", "Learn about Tuckman's stages of group development for the ASWB exam.", ["Tuckman", "group stages", "forming", "storming", "norming", "performing", "ASWB"], "Tuckman's model describes five stages all groups progress through.", "Forming (orientation, leader dependence), Storming (conflict, resistance, power struggles), Norming (cohesion, norms established), Performing (productive work, interdependence), Adjourning (termination, evaluation). Leader role changes: more directive early, more facilitative later.", "Frequently tested on the ASWB exam.", "Groups may revisit earlier stages with new members, crises, or transitions.", "Identify current stage and adapt leadership.", "More structure early, transition to facilitation as group matures.", "Failing to recognize storming as normal can lead to premature termination.", ["Forming: orientation and leader dependence", "Storming: conflict, a normal necessary stage", "Norming: cohesion and role clarification", "Performing: productive work and interdependence"], ["Not knowing stages in order", "Not recognizing storming as normal", "Expecting performing during forming"], [{question: "What are Tuckman's five stages?", answer: "Forming, Storming, Norming, Performing, and Adjourning."}, {question: "Is the storming stage a bad sign?", answer: "No. Storming (conflict, resistance, power struggles) is a normal and necessary stage of group development. Attempting to avoid it can prevent the group from progressing."}]),

  e("group-types-social-work", "Types of Groups in Social Work", "Group Work", "Types of Groups | ASWB Guide", "Learn about different types of groups for the ASWB exam.", ["group types", "therapy groups", "support groups", "psychoeducational", "task groups", "ASWB"], "Social workers facilitate various group types with distinct purposes and leadership approaches.", "Treatment/Therapy: personal growth through process. Support: mutual aid with shared experience. Psychoeducational: structured skill-teaching. Task: organizational/community goals. Self-Help: peer-led without professional (AA, NA).", "Tested on the ASWB exam.", "Therapy=process; psychoeducational=content; support=shared experience; task=goal accomplishment.", "Select type based on client needs and treatment goals. Screen for appropriateness.", "Leader role varies: facilitation (therapy), content delivery (psychoeducational), sharing facilitation (support), organizational (task).", "Wrong group type is ineffective. Same approach won't work for all types.", ["Treatment: growth; task: goals", "Support: mutual aid; psychoeducational: learning", "Self-help: peer-led; therapy: professional", "Leader role varies by type"], ["Confusing therapy with psychoeducational", "Same approach for all types", "Not screening for membership"], [{question: "What is the difference between therapy and psychoeducational groups?", answer: "Therapy groups focus on interpersonal process and personal growth. Psychoeducational groups focus on structured content delivery and skill-building."}, {question: "What is a task group?", answer: "A group focused on accomplishing an organizational or community goal, emphasizing task completion rather than personal growth."}]),

  // ===== FAMILY SYSTEMS =====
  e("bowen-family-systems-detailed", "Bowen Family Systems Theory (Detailed)", "Family Systems", "Bowen Family Systems | ASWB Guide", "Learn about Bowen's key concepts for the ASWB exam.", ["Bowen", "differentiation", "triangulation", "multigenerational", "ASWB"], "Murray Bowen's theory views the family as an emotional unit, explaining how families function and transmit patterns across generations.", "Eight concepts: (1) Differentiation of Self (separating thinking from feeling), (2) Triangles (three-person system), (3) Nuclear Family Emotional System, (4) Family Projection Process (transmitting anxiety to children), (5) Multigenerational Transmission, (6) Emotional Cutoff (distance for unresolved issues), (7) Sibling Position, (8) Societal Emotional Process.", "Tested on the ASWB exam.", "High differentiation = healthy functioning. Low differentiation = fusion and reactivity.", "Genogram maps family patterns across three+ generations.", "Increase differentiation, detriangle from conflicts, address multigenerational patterns.", "Emotional cutoff appears as independence but reflects unresolved issues.", ["Differentiation is the core concept", "Triangles are the basic emotional unit", "Genograms map multigenerational patterns", "Emotional cutoff is not healthy independence"], ["Confusing differentiation with cutoff", "Not understanding triangulation", "Confusing Bowen with structural therapy"], [{question: "What is differentiation of self?", answer: "The ability to separate thinking from feeling and to maintain one's sense of self while in emotional contact with others."}, {question: "What is emotional cutoff?", answer: "Managing unresolved family issues through emotional distance or physical separation. It appears as independence but reflects avoidance of unresolved attachment issues."}]),

  e("systems-theory-social-work", "Systems Theory in Social Work", "Family Systems", "Systems Theory | ASWB Guide", "Learn about general systems theory in social work for the ASWB exam.", ["systems theory", "von Bertalanffy", "homeostasis", "equifinality", "ASWB"], "General systems theory (von Bertalanffy) views all levels (individuals, families, communities) as interconnected systems.", "Key concepts: system, subsystems, suprasystems, boundaries (open/closed/semi-permeable), homeostasis (maintaining stability), feedback loops (positive amplifies, negative maintains), equifinality (same outcome, different pathways), entropy (tendency toward disorder).", "Foundational to social work and tested on the ASWB exam.", "Dysfunction in one part affects the entire system.", "Assess boundaries, communication, roles, rules, hierarchy, homeostatic mechanisms.", "Target any system level for positive change.", "Viewing problems as solely individual ignores systemic factors.", ["Changes in one part affect all others", "Homeostasis maintains stability, even dysfunctional", "Equifinality: same outcome, different pathways", "Boundaries: open, closed, or semi-permeable"], ["Confusing concepts", "Not recognizing systemic patterns", "Viewing problems as solely individual"], [{question: "What is homeostasis?", answer: "The system's tendency to maintain its current state, even if dysfunctional. Systems resist change to preserve stability."}, {question: "What is equifinality?", answer: "The same outcome can be reached through different pathways. Similar problems can develop from different origins and be resolved through different interventions."}]),

  // ===== MENTAL HEALTH DISORDERS =====
  e("anxiety-disorders", "Anxiety Disorders", "Mental Health Disorders", "Anxiety Disorders | ASWB Guide", "Learn about anxiety disorders for the ASWB exam.", ["anxiety disorders", "GAD", "panic disorder", "phobias", "ASWB"], "Anxiety disorders are the most common mental health disorders, characterized by excessive fear and anxiety.", "GAD (excessive worry, 6+ months), Panic Disorder (unexpected panic attacks), Social Anxiety (fear of social situations), Specific Phobias (irrational fear of objects/situations), Agoraphobia (fear where escape is difficult). DSM-5 separated OCD and PTSD.", "Tested on the ASWB exam in clinical assessment and treatment.", "Excessive worry, restlessness, fatigue, concentration difficulty, muscle tension, sleep disturbance, avoidance.", "Symptom evaluation, differential diagnosis, functional impairment, GAD-7 screening.", "CBT (gold standard), exposure therapy, SSRIs/SNRIs, relaxation training, mindfulness.", "Avoidance maintains anxiety; treatment requires gradual exposure.", ["GAD: excessive worry for 6+ months", "CBT is the gold standard", "Exposure therapy for phobias and OCD", "OCD and PTSD are no longer anxiety disorders in DSM-5"], ["Confusing different anxiety disorders", "Not knowing OCD/PTSD reclassification", "Not recognizing avoidance maintains anxiety"], [{question: "What is the gold standard treatment for anxiety?", answer: "CBT, often including exposure therapy, is the gold standard. Medication (SSRIs/SNRIs) may supplement therapy."}, {question: "Why did DSM-5 separate OCD and PTSD from anxiety?", answer: "While they share features with anxiety disorders, OCD and PTSD have distinct etiologies, presentations, and treatment approaches warranting separate diagnostic categories."}]),

  e("depressive-disorders", "Depressive Disorders", "Mental Health Disorders", "Depressive Disorders | ASWB Guide", "Learn about depressive disorders for the ASWB exam.", ["depression", "major depressive disorder", "dysthymia", "PHQ-9", "ASWB"], "Mood disorders characterized by persistent sadness, loss of interest, and functional impairment.", "MDD: 5+ symptoms for 2+ weeks including depressed mood or anhedonia. PDD/Dysthymia: depressed mood most days for 2+ years. PHQ-9 is standard screening.", "Tested on the ASWB exam.", "Weight/appetite changes, sleep disturbance, psychomotor changes, fatigue, worthlessness, concentration difficulty, suicidal ideation.", "Screen with PHQ-9, assess severity, suicidal ideation, rule out medical causes and bipolar.", "CBT, behavioral activation, interpersonal therapy, SSRIs, exercise, combined approaches.", "Failing to assess for suicidal ideation or rule out bipolar disorder.", ["MDD: 5+ symptoms for 2+ weeks", "PDD: depressed mood most days for 2+ years", "Always assess for suicidal ideation", "Rule out bipolar and medical causes"], ["Confusing MDD with PDD", "Not assessing for suicidal ideation", "Not ruling out bipolar"], [{question: "What are the criteria for MDD?", answer: "Five or more symptoms for two or more weeks, including at least depressed mood or anhedonia (loss of interest/pleasure)."}, {question: "What is the PHQ-9?", answer: "A 9-item standardized depression screening tool scoring 0-27, widely used in healthcare and mental health settings."}]),

  e("personality-disorders", "Personality Disorders", "Mental Health Disorders", "Personality Disorders | ASWB Guide", "Learn about personality disorders for the ASWB exam.", ["personality disorders", "borderline", "Cluster A B C", "ASWB"], "Enduring patterns of inner experience and behavior deviating from cultural expectations, pervasive and inflexible.", "Cluster A (odd): Paranoid, Schizoid, Schizotypal. Cluster B (dramatic): Antisocial, Borderline, Histrionic, Narcissistic. Cluster C (anxious): Avoidant, Dependent, OCPD. BPD: emotional instability, abandonment fears, identity disturbance. DBT is evidence-based for BPD.", "Tested on the ASWB exam.", "Ego-syntonic (part of self) rather than ego-dystonic, making engagement challenging.", "Patterns must be enduring, pervasive, inflexible, and not explained by another disorder.", "DBT for BPD, schema therapy, mentalization-based therapy. Long-term, consistent boundaries.", "Countertransference is common. Splitting disrupts treatment teams.", ["Cluster A=odd, B=dramatic, C=anxious", "BPD: emotional instability, abandonment fears", "DBT is evidence-based for BPD", "Ego-syntonic"], ["Confusing clusters", "Not recognizing countertransference", "Confusing OCPD with OCD"], [{question: "What are the three clusters?", answer: "Cluster A (odd/eccentric), Cluster B (dramatic/emotional), Cluster C (anxious/fearful)."}, {question: "What is DBT?", answer: "Dialectical Behavior Therapy, developed by Marsha Linehan for Borderline Personality Disorder. It combines CBT with mindfulness and teaches distress tolerance, emotion regulation, and interpersonal effectiveness."}]),

  e("ptsd-and-trauma", "PTSD and Trauma Disorders", "Mental Health Disorders", "PTSD and Trauma | ASWB Guide", "Learn about PTSD and trauma-related disorders for the ASWB exam.", ["PTSD", "trauma", "acute stress disorder", "ASWB"], "PTSD and trauma disorders are in the DSM-5 Trauma- and Stressor-Related Disorders category.", "PTSD requires trauma exposure. Four clusters: intrusion (flashbacks), avoidance, negative cognitions/mood, arousal/reactivity. Duration 1+ month. Acute Stress Disorder: 3 days to 1 month. Complex trauma: prolonged, repeated.", "Tested on the ASWB exam in clinical assessment and treatment.", "Flashbacks, nightmares, avoidance, emotional numbing, hypervigilance, exaggerated startle, sleep difficulty.", "Trauma history (sensitively), symptom evaluation, PCL-5, functional impairment, safety.", "TF-CBT, CPT, Prolonged Exposure, EMDR. Trauma-informed care principles.", "Premature exposure to trauma material can retraumatize.", ["DSM-5 moved PTSD from anxiety to Trauma category", "Four clusters: intrusion, avoidance, negative cognitions, arousal", "ASD: 3 days to 1 month; PTSD: 1+ month", "TF-CBT, CPT, PE, EMDR are evidence-based"], ["Confusing PTSD with ASD", "Not knowing symptom clusters", "Not recognizing complex trauma"], [{question: "What are the four PTSD symptom clusters?", answer: "Intrusion (flashbacks, nightmares), avoidance, negative cognitions and mood, and arousal/reactivity."}, {question: "What is the difference between ASD and PTSD?", answer: "Acute Stress Disorder lasts 3 days to 1 month after trauma. PTSD is diagnosed when symptoms persist beyond 1 month."}]),

  e("schizophrenia-spectrum", "Schizophrenia Spectrum Disorders", "Mental Health Disorders", "Schizophrenia Spectrum | ASWB Guide", "Learn about schizophrenia spectrum disorders for the ASWB exam.", ["schizophrenia", "psychosis", "positive symptoms", "negative symptoms", "ASWB"], "Schizophrenia involves disturbances in thought, perception, emotion, and behavior, including psychotic features.", "Requires 2+ symptoms for 1+ month (at least one must be delusions, hallucinations, or disorganized speech), continuous disturbance for 6+ months. Positive: delusions, hallucinations, disorganized speech. Negative: flat affect, avolition, alogia, anhedonia. Onset late adolescence/early adulthood.", "Tested on the ASWB exam.", "Assess medication adherence, symptom severity, functional capacity, safety, support systems.", "Psychiatric evaluation, functional assessment, family history, substance use screening.", "Antipsychotics, psychosocial rehabilitation, supported employment, family psychoeducation, ACT.", "Focusing only on positive symptoms while neglecting negative symptoms and rehabilitation.", ["Positive: delusions, hallucinations, disorganized speech", "Negative: flat affect, avolition, alogia, anhedonia", "Negative symptoms are often more disabling", "Onset in late adolescence/early adulthood"], ["Confusing positive and negative symptoms", "Not knowing duration criteria", "Ignoring negative symptoms in treatment"], [{question: "What are positive symptoms?", answer: "Symptoms added to normal experience: delusions, hallucinations, disorganized speech and behavior."}, {question: "What are negative symptoms?", answer: "Functions subtracted from normal experience: flat affect, avolition (lack of motivation), alogia (poverty of speech), anhedonia (inability to experience pleasure)."}]),

  e("bipolar-disorders", "Bipolar Disorders", "Mental Health Disorders", "Bipolar Disorders | ASWB Guide", "Learn about bipolar disorders for the ASWB exam.", ["bipolar disorder", "mania", "hypomania", "ASWB"], "Bipolar disorders involve episodes of mania/hypomania alternating with depression.", "Bipolar I: at least one manic episode (elevated mood, decreased sleep need, grandiosity, pressured speech, racing thoughts, risky behavior; 1+ week or hospitalization). Bipolar II: hypomanic episode (less severe, 4+ days) and major depressive episode. Cyclothymic: chronic fluctuating mood for 2+ years.", "Tested on the ASWB exam.", "Mania: euphoria, irritability, decreased sleep, grandiosity, pressured speech, risky behavior.", "Mood history, family history (strong genetic component), substance use screening, rule out medical causes.", "Mood stabilizers (lithium, valproate) first-line. Antidepressant monotherapy can trigger mania. Psychoeducation, CBT, family therapy.", "Antidepressant monotherapy without mood stabilizers can trigger mania.", ["Bipolar I requires mania; Bipolar II requires hypomania", "Mania: 1+ week; hypomania: 4+ days", "Antidepressant monotherapy can trigger mania", "Mood stabilizers are first-line"], ["Confusing Bipolar I with II", "Not knowing mania vs. hypomania", "Prescribing antidepressants without ruling out bipolar"], [{question: "What is the difference between mania and hypomania?", answer: "Mania is more severe (1+ week, may require hospitalization, causes marked impairment). Hypomania is less severe (4+ days, no hospitalization, functioning is not markedly impaired)."}, {question: "Why is antidepressant monotherapy dangerous in bipolar?", answer: "Antidepressants without mood stabilizers can trigger a manic episode in people with bipolar disorder."}]),

  // ===== ADDITIONAL ENTRIES =====
  e("substance-use-disorders", "Substance Use Disorders", "Substance Abuse", "Substance Use Disorders | ASWB Guide", "Learn about substance use disorder diagnosis and assessment for the ASWB exam.", ["substance use disorder", "addiction", "DSM-5 criteria", "ASWB"], "The DSM-5 replaced substance abuse and dependence with a single substance use disorder diagnosis on a severity continuum (mild, moderate, severe).", "DSM-5 criteria (need 2+ of 11): larger amounts/longer than intended, persistent desire to cut down, great deal of time obtaining/using/recovering, craving, failure to fulfill obligations, continued use despite social problems, giving up activities, use in hazardous situations, continued despite physical/psychological problems, tolerance, withdrawal. Mild=2-3, Moderate=4-5, Severe=6+.", "Tested on the ASWB exam in clinical assessment.", "Craving, tolerance, withdrawal, loss of control, and continued use despite consequences.", "AUDIT, DAST, CAGE, comprehensive substance use history, biopsychosocial assessment.", "Evidence-based treatments vary by substance: MAT for opioids/alcohol, CBT, MI, contingency management, therapeutic communities.", "Physical withdrawal from alcohol and benzodiazepines can be medically dangerous and potentially fatal.", ["DSM-5 uses a single SUD diagnosis on a continuum", "11 criteria; 2+=mild, 4+=moderate, 6+=severe", "DSM-5 added craving and removed legal problems as criteria", "Alcohol and benzodiazepine withdrawal can be fatal"], ["Using outdated abuse/dependence terminology", "Not knowing DSM-5 SUD criteria", "Not recognizing dangerous withdrawal syndromes"], [{question: "How did DSM-5 change substance disorders?", answer: "Combined abuse and dependence into a single substance use disorder on a severity continuum, added craving, and removed legal problems from criteria."}, {question: "Which substance withdrawals are medically dangerous?", answer: "Alcohol and benzodiazepine withdrawal can cause seizures and be potentially fatal. Medical detoxification is essential."}]),

  e("social-work-ethics-values", "Social Work Values and Ethics", "Ethics & Legal Issues", "Social Work Values and Ethics | ASWB Guide", "Learn about core social work values and ethical principles for the ASWB exam.", ["social work values", "ethics", "NASW", "service", "dignity", "ASWB"], "The NASW Code of Ethics establishes six core values and corresponding ethical principles that guide social work practice.", "Six core values: Service (help people in need), Social Justice (challenge social injustice), Dignity and Worth of the Person (respect inherent dignity), Importance of Human Relationships (central to change), Integrity (behave trustworthily), Competence (practice within competence). The Code addresses responsibilities to clients, colleagues, practice settings, profession, and broader society.", "Core values and the NASW Code of Ethics are among the most tested topics on the ASWB exam.", "Ethical dilemmas arise when two or more ethical principles conflict. Social workers must use ethical decision-making models to resolve these conflicts.", "Assessment of ethical issues requires identifying the relevant Code sections, stakeholders, options, and potential consequences of each option.", "Apply ethical decision-making frameworks (Reamer, Loewenberg and Dolgoff), consult with supervisors and colleagues, consider laws and regulations, and document the decision-making process.", "Violating the Code of Ethics can result in disciplinary action, license revocation, and legal liability.", ["Six core values: service, social justice, dignity, relationships, integrity, competence", "Client well-being is the primary obligation", "When values conflict, use ethical decision-making models", "Consult with supervisors when facing ethical dilemmas"], ["Not knowing the six core values", "Not recognizing ethical dilemmas in practice scenarios", "Failing to use a systematic ethical decision-making process"], [{question: "What are the six core values?", answer: "Service, social justice, dignity and worth of the person, importance of human relationships, integrity, and competence."}, {question: "What is the primary obligation in social work ethics?", answer: "The well-being of the client is the primary obligation, though this must be balanced with responsibility to the broader society in certain circumstances."}]),

  e("record-keeping-documentation", "Record Keeping and Documentation", "Ethics & Legal Issues", "Record Keeping in Social Work | ASWB Guide", "Learn about record keeping and documentation standards for the ASWB exam.", ["record keeping", "documentation", "clinical records", "HIPAA", "ASWB"], "Accurate and timely documentation is both an ethical obligation and a legal requirement in social work. Records serve multiple purposes: continuity of care, legal protection, accountability, and communication.", "NASW Code of Ethics (Section 3.04) requires documentation sufficient to facilitate service delivery and ensure continuity. Records should include assessments, treatment plans, progress notes, informed consent, and termination summaries. HIPAA establishes standards for protected health information (PHI). The minimum necessary standard requires disclosing only information needed for the purpose.", "Documentation and record keeping are tested on the ASWB exam in ethics and practice contexts.", "Progress notes should be timely, accurate, objective, relevant, and legible. Use behavioral descriptions rather than judgmental language.", "Assess what information needs to be documented based on professional standards, agency policy, and legal requirements.", "Document concurrently with services when possible. Use SOAP or DAP note formats. Store records securely. Retain records according to state law and agency policy.", "Poor documentation increases liability risk. Records can be subpoenaed in legal proceedings.", ["Document sufficient to facilitate service delivery", "HIPAA minimum necessary standard applies", "Use objective, behavioral descriptions", "Records can be subpoenaed in court"], ["Not knowing HIPAA requirements", "Using subjective language in clinical records", "Not documenting informed consent"], [{question: "What is HIPAA's minimum necessary standard?", answer: "When sharing protected health information, disclose only the minimum amount necessary for the specific purpose."}, {question: "What should progress notes include?", answer: "Date, relevant session content, client presentation, interventions used, client response, and plans. Use objective, behavioral language."}]),

  e("hipaa-and-confidentiality", "HIPAA and Confidentiality", "Ethics & Legal Issues", "HIPAA in Social Work | ASWB Guide", "Learn about HIPAA regulations and confidentiality in social work for the ASWB exam.", ["HIPAA", "confidentiality", "PHI", "privacy", "ASWB"], "HIPAA (Health Insurance Portability and Accountability Act) establishes national standards for protecting health information. Social workers must understand HIPAA requirements alongside professional confidentiality obligations.", "HIPAA Privacy Rule protects PHI (Protected Health Information). Key provisions: minimum necessary standard, client right to access records, authorization required for most disclosures, Notice of Privacy Practices must be provided, breach notification requirements. Exceptions to confidentiality include: duty to warn/protect, mandated reporting, court orders, and emergencies.", "HIPAA and confidentiality are frequently tested on the ASWB exam.", "PHI includes any individually identifiable health information. Social workers must protect PHI in all formats (paper, electronic, verbal).", "Assess whether a disclosure is permitted or requires authorization. Identify the appropriate exception if applicable.", "Provide Notice of Privacy Practices. Obtain authorization before disclosure unless an exception applies. Document all disclosures. Implement security measures for electronic PHI.", "Unauthorized disclosure of PHI can result in civil and criminal penalties.", ["HIPAA protects PHI in all formats", "Minimum necessary standard applies to disclosures", "Clients have the right to access their records", "Know the exceptions to confidentiality"], ["Not knowing HIPAA exceptions to confidentiality", "Disclosing more than the minimum necessary", "Confusing HIPAA with FERPA"], [{question: "What are exceptions to confidentiality under HIPAA?", answer: "Duty to warn/protect, mandated reporting, court orders, emergencies, and some public health and law enforcement purposes."}, {question: "Do clients have the right to access their records?", answer: "Yes. Under HIPAA, clients have the right to access, inspect, and obtain copies of their health records with limited exceptions."}]),

  e("elder-abuse-and-neglect", "Elder Abuse and Neglect", "Ethics & Legal Issues", "Elder Abuse in Social Work | ASWB Guide", "Learn about elder abuse types, indicators, and reporting for the ASWB exam.", ["elder abuse", "adult protective services", "APS", "geriatric", "ASWB"], "Elder abuse includes physical, sexual, emotional, and financial abuse, as well as neglect and self-neglect of older adults. Social workers in most states are mandated reporters of elder abuse.", "Types: physical abuse (hitting, restraining), sexual abuse, emotional/psychological abuse (threats, isolation, humiliation), financial exploitation (theft, fraud, undue influence), neglect (failure to provide care), self-neglect (refusal or inability to meet own needs). Risk factors include caregiver stress, social isolation, cognitive impairment, and financial dependence.", "Elder abuse is tested on the ASWB exam in the context of ethics, legal issues, and aging.", "Indicators: unexplained injuries, withdrawal, fearfulness, financial irregularities, poor hygiene, malnutrition, dehydration, and caregiver who is controlling or dismissive.", "Interview the older adult privately. Assess safety, cognitive capacity, and degree of risk. Document observations.", "Report to Adult Protective Services (APS). Develop safety plan. Connect with legal services. Address caregiver stress when appropriate.", "Failure to report elder abuse is a legal violation in most states.", ["Social workers in most states are mandated reporters of elder abuse", "Financial exploitation is the most common form of elder abuse", "Interview the older adult privately, separate from the suspected abuser", "Self-neglect is a form of elder abuse that raises complex ethical issues"], ["Not recognizing financial exploitation as elder abuse", "Not interviewing the elder privately", "Confusing elder abuse reporting with child abuse reporting procedures"], [{question: "What types of elder abuse exist?", answer: "Physical, sexual, emotional/psychological, financial exploitation, neglect, and self-neglect."}, {question: "How is elder abuse reported?", answer: "Report to Adult Protective Services (APS), the adult equivalent of CPS. Most states mandate social workers as reporters."}]),

  e("social-work-licensing", "Social Work Licensing", "Ethics & Legal Issues", "Social Work Licensing | ASWB Guide", "Learn about social work licensing levels and requirements for the ASWB exam.", ["licensing", "LCSW", "LMSW", "ASWB exam", "ASWB"], "Social work licensing protects the public by ensuring practitioners meet minimum competency standards. Licensing is regulated by each state through social work licensing boards.", "ASWB administers four exam levels: Bachelors (BSW-level), Masters (MSW-level generalist), Advanced Generalist (post-master experience), and Clinical (independent clinical practice). Common license types include LSW/LBSW (bachelor level), LMSW/LGSW (master level), and LCSW/LICSW (clinical level). Requirements typically include degree, supervised experience (2-3 years for clinical), passing the appropriate ASWB exam, and continuing education.", "Understanding licensing is fundamental to ASWB exam preparation.", "Practicing without a license or outside one's scope of practice is illegal and unethical.", "Assess whether your education, experience, and competencies align with the scope of practice for your license level.", "Maintain license through continuing education, supervision (for pre-licensure), and adherence to ethical standards.", "Practicing outside one's scope of practice or without proper licensure can result in legal action and harm to clients.", ["Licensing is regulated by each state", "ASWB administers four exam levels", "Clinical license typically requires 2-3 years supervised post-master experience", "Continuing education is required for license renewal"], ["Not understanding scope of practice for different license levels", "Not knowing the difference between LMSW and LCSW", "Practicing outside one's scope"], [{question: "What are the ASWB exam levels?", answer: "Bachelors, Masters, Advanced Generalist, and Clinical, corresponding to different education and experience levels."}, {question: "What is required for an LCSW?", answer: "Typically an MSW degree, 2-3 years of supervised clinical experience (varies by state), passing the ASWB Clinical exam, and state-specific requirements."}]),

  e("cultural-formulation-interview", "Cultural Formulation Interview", "Cultural Competence", "Cultural Formulation Interview | ASWB Guide", "Learn about the DSM-5 Cultural Formulation Interview for the ASWB exam.", ["cultural formulation", "CFI", "cultural assessment", "DSM-5", "ASWB"], "The DSM-5 Cultural Formulation Interview (CFI) is a standardized approach to assessing cultural factors affecting diagnosis, treatment, and the clinical encounter.", "The CFI consists of 16 questions organized into four domains: Cultural Definition of the Problem (how the individual understands their problem), Cultural Perceptions of Cause/Context (what the individual thinks caused the problem), Cultural Factors Affecting Self-Coping and Past Help Seeking (coping and past treatment), and Cultural Factors Affecting Current Help Seeking (barriers and preferences for current treatment).", "Cultural assessment is tested on the ASWB exam in diversity and clinical practice contexts.", "Cultural factors influence how individuals experience, express, and seek help for mental health problems.", "Use the CFI to explore the client's cultural understanding of their problem, past help-seeking, and treatment preferences.", "Integrate CFI findings into diagnostic formulation and treatment planning. Adapt interventions to the client's cultural context.", "Ignoring cultural factors can lead to misdiagnosis and ineffective treatment.", ["The CFI is included in the DSM-5", "Four domains: definition, cause, coping/past help, current help-seeking", "Cultural factors affect symptom expression and help-seeking", "Use CFI findings in treatment planning"], ["Not assessing cultural factors in diagnosis", "Assuming cultural factors only apply to minority clients", "Not adapting treatment to cultural context"], [{question: "What is the CFI?", answer: "A DSM-5 standardized set of 16 questions for assessing how cultural factors affect the clinical encounter, organized into four domains."}, {question: "Who should the CFI be used with?", answer: "All clients, not just those from minority backgrounds. Cultural factors affect everyone's experience of health and illness."}]),

  e("medical-social-work", "Medical Social Work", "Community Practice", "Medical Social Work | ASWB Guide", "Learn about medical social work practice and roles for the ASWB exam.", ["medical social work", "hospital social work", "discharge planning", "interdisciplinary team", "ASWB"], "Medical social workers practice in hospitals, clinics, rehabilitation facilities, and other healthcare settings. They address psychosocial needs, facilitate discharge planning, and serve on interdisciplinary teams.", "Key functions: psychosocial assessment, discharge planning (including post-acute care arrangements), advance directives counseling, grief and bereavement support, resource linkage, insurance navigation, family support, and crisis intervention. Medical social workers must understand health literacy, cultural factors in health, and the impact of illness on patients and families.", "Medical social work is tested on the ASWB exam in practice settings and interdisciplinary contexts.", "Patients and families facing illness, hospitalization, disability, and end-of-life issues experience stress, grief, fear, and practical challenges.", "Psychosocial assessment including coping, support systems, financial resources, insurance status, home environment, and advance care planning status.", "Discharge planning, advance directives, resource linkage, counseling, family meetings, insurance navigation, and advocacy.", "Premature discharge without adequate planning can result in readmission. Failure to address advance directives can lead to unwanted interventions.", ["Discharge planning is a core medical social work function", "Advance directives should be discussed with all adult patients", "Medical social workers serve on interdisciplinary teams", "Health literacy affects patient understanding and adherence"], ["Not understanding discharge planning processes", "Not knowing advance directive types", "Confusing interdisciplinary with multidisciplinary teams"], [{question: "What is the difference between interdisciplinary and multidisciplinary teams?", answer: "Interdisciplinary teams collaborate, share decisions, and integrate perspectives. Multidisciplinary teams consult independently without integration."}, {question: "What are advance directives?", answer: "Legal documents expressing a person's wishes for end-of-life care, including living wills and healthcare power of attorney."}]),

  e("hospice-and-palliative-care", "Hospice and Palliative Care", "Community Practice", "Hospice and Palliative Care | ASWB Guide", "Learn about hospice and palliative care social work for the ASWB exam.", ["hospice", "palliative care", "end of life", "bereavement", "ASWB"], "Social workers are required members of the hospice interdisciplinary team. Hospice provides comfort-focused care for individuals with a terminal prognosis of six months or less.", "Hospice: comfort care (not curative) for terminal illness, Medicare benefit requires 6-month prognosis, includes medical, nursing, social work, chaplain, and volunteer services, bereavement support for 13 months post-death. Palliative care: can be provided alongside curative treatment, focuses on symptom management and quality of life at any stage of serious illness. Social workers provide counseling, advance care planning, family support, and resource coordination.", "Hospice and palliative care are tested on the ASWB exam.", "Patients and families experience anticipatory grief, fear, spiritual distress, family conflict, and practical concerns (financial, caregiving burden).", "Psychosocial assessment including grief/coping, family dynamics, spiritual needs, advance care planning, and practical needs.", "Counseling, family meetings, advance care planning, grief support, resource coordination, and bereavement follow-up for 13 months.", "Failing to discuss hospice early enough limits time for quality end-of-life care.", ["Hospice requires 6-month terminal prognosis", "Palliative care can be provided alongside curative treatment", "Social workers are required on the hospice team", "Bereavement support continues 13 months post-death"], ["Confusing hospice with palliative care", "Not knowing the Medicare hospice benefit", "Not understanding anticipatory grief"], [{question: "What is the difference between hospice and palliative care?", answer: "Hospice is comfort care for terminal illness (6-month prognosis). Palliative care focuses on symptom management and quality of life at any stage of serious illness, alongside curative treatment."}, {question: "How long does bereavement support last?", answer: "Hospice programs provide bereavement support to the family for 13 months following the death."}]),

  e("military-social-work", "Military Social Work", "Community Practice", "Military Social Work | ASWB Guide", "Learn about military social work and veteran services for the ASWB exam.", ["military social work", "veterans", "VA", "military culture", "ASWB"], "Military social workers serve active duty service members, veterans, and military families in Department of Defense, VA, and community settings.", "Key issues: PTSD, traumatic brain injury (TBI), military sexual trauma (MST), substance use, transition challenges, family separation, deployment stress, moral injury, and suicide risk (veterans have elevated suicide rates). Military culture values include mission focus, hierarchy, unit cohesion, stoicism, and self-reliance. Social workers must understand military culture to provide effective services.", "Military and veteran issues are tested on the ASWB exam.", "Service members may present with PTSD, TBI, MST, depression, substance use, relationship difficulties, and transition adjustment.", "Culturally competent assessment considering military culture, deployment history, combat exposure, MST, TBI, and family impact.", "Evidence-based trauma treatment (CPT, PE, EMDR), substance abuse treatment, family therapy, transition support, and VA benefits navigation.", "Military culture's emphasis on stoicism and self-reliance can be a barrier to help-seeking. Clinician unfamiliarity with military culture can damage rapport.", ["Veterans have elevated suicide rates", "Military sexual trauma affects both men and women", "Understanding military culture is essential for rapport", "PTSD, TBI, and MST frequently co-occur"], ["Not understanding military culture and values", "Assuming all veterans have PTSD", "Not assessing for military sexual trauma"], [{question: "What is military sexual trauma?", answer: "Sexual assault or repeated sexual harassment experienced during military service. It affects both men and women service members."}, {question: "Why is military culture important in treatment?", answer: "Military culture values stoicism, mission focus, and self-reliance, which can be barriers to help-seeking. Understanding this culture builds rapport and trust."}]),

  e("substance-abuse-assessment", "Substance Abuse Assessment", "Substance Abuse", "Substance Abuse Assessment | ASWB Guide", "Learn about substance abuse assessment methods and tools for the ASWB exam.", ["substance abuse assessment", "CAGE", "AUDIT", "DAST", "screening", "ASWB"], "Comprehensive substance abuse assessment is essential for accurate diagnosis, appropriate level of care determination, and treatment planning.", "Assessment components: substance use history (types, amounts, frequency, route, duration, last use), consequences (medical, legal, social, occupational, financial), family history of addiction, previous treatment history, readiness for change, co-occurring disorders, and strengths/resources. Common screening tools: CAGE (4 yes/no questions; 2+ positive), AUDIT (alcohol, 10 items), DAST (drugs, 10/20/28 items), CRAFFT (adolescents), and SBIRT (Screening, Brief Intervention, and Referral to Treatment).", "Substance abuse assessment is tested on the ASWB exam.", "Signs of substance use: tolerance, withdrawal, increasing use, failed attempts to cut down, time spent obtaining/using, giving up activities, continued use despite problems.", "Use validated screening tools, comprehensive clinical interview, collateral information, and laboratory findings when available.", "ASAM criteria determine level of care: outpatient, intensive outpatient, partial hospitalization, residential, or medically managed detoxification.", "Minimizing substance use in assessment can lead to under-treatment. Not assessing for co-occurring disorders misses critical clinical information.", ["CAGE: 2+ positive answers suggest problem drinking", "AUDIT is the most widely used alcohol screening tool", "SBIRT integrates screening into primary care settings", "ASAM criteria determine appropriate level of care"], ["Not knowing common screening tools", "Not assessing for co-occurring disorders", "Confusing screening with comprehensive assessment"], [{question: "What is SBIRT?", answer: "Screening, Brief Intervention, and Referral to Treatment: an evidence-based approach for integrating substance abuse screening into primary care and other settings."}, {question: "What are the CAGE questions?", answer: "Have you felt you should Cut down? Have people Annoyed you about drinking? Have you felt Guilty? Have you needed an Eye-opener? Two or more positive answers suggest a drinking problem."}]),

  e("social-work-with-children", "Social Work with Children", "Child Welfare", "Social Work with Children | ASWB Guide", "Learn about child-centered practice approaches for the ASWB exam.", ["child therapy", "play therapy", "child assessment", "developmental", "ASWB"], "Social workers serving children must use developmentally appropriate assessment and intervention techniques. Children communicate primarily through play and behavior rather than verbal expression.", "Child-centered approaches include play therapy (directive and non-directive), art therapy, sand tray therapy, storytelling, and bibliotherapy. Assessment adaptations for children include using age-appropriate language, shorter sessions, movement and sensory activities, and involving caregivers. Understanding child development stages is essential for appropriate communication and intervention.", "Child-specific practice approaches are tested on the ASWB exam.", "Children may express distress through behavioral changes, regression, somatic complaints, separation anxiety, changes in eating/sleeping, and academic problems rather than verbal complaints.", "Use developmentally appropriate assessment tools, observe play, gather collateral information from parents and teachers, and assess the family system.", "Play therapy, behavioral interventions, parent training/management, family therapy, and school-based interventions. Involve caregivers in treatment.", "Using adult-oriented therapeutic approaches with young children is ineffective. Not involving caregivers limits treatment success.", ["Children communicate through play and behavior", "Developmentally appropriate language and activities are essential", "Involve caregivers in assessment and treatment", "Behavioral changes may indicate distress rather than defiance"], ["Using adult therapy techniques with young children", "Not involving caregivers in treatment", "Interpreting behavioral symptoms as defiance rather than distress"], [{question: "Why is play therapy used with children?", answer: "Children communicate primarily through play rather than verbal expression. Play therapy provides a developmentally appropriate medium for children to express feelings, process experiences, and develop coping skills."}, {question: "Why involve caregivers in child treatment?", answer: "Caregivers are the primary agents of change. Involving them improves outcomes, ensures generalization of skills, and addresses family dynamics affecting the child."}]),

  e("gerontological-social-work", "Gerontological Social Work", "Community Practice", "Gerontological Social Work | ASWB Guide", "Learn about social work practice with older adults for the ASWB exam.", ["gerontological", "aging", "older adults", "geriatric", "ASWB"], "Gerontological social workers address the unique needs of older adults across healthcare, community, and long-term care settings.", "Key issues: chronic illness management, dementia and cognitive decline, depression (often underdiagnosed in older adults), grief and loss (cumulative losses), caregiver stress and burden, elder abuse, end-of-life planning, housing transitions (independent to assisted living to nursing home), medication management, social isolation, and ageism. Erikson's final stage: Integrity vs. Despair.", "Gerontological practice is tested on the ASWB exam.", "Older adults may present with depression (often somatized), cognitive decline, grief from cumulative losses, social isolation, and anxiety about dependency and death.", "Comprehensive geriatric assessment including cognitive screening (MMSE, MoCA), depression screening (GDS), functional assessment (ADLs, IADLs), fall risk, social support, and safety.", "Counseling, care coordination, caregiver support, advance care planning, community resource linkage, advocacy, and end-of-life services.", "Depression in older adults is often undiagnosed because symptoms are attributed to aging. Ageist assumptions can lead to under-treatment.", ["Depression is commonly underdiagnosed in older adults", "Cumulative losses are a major challenge in aging", "ADLs and IADLs measure functional capacity", "Erikson's Integrity vs. Despair applies to late life"], ["Attributing depression symptoms to normal aging", "Making ageist assumptions about treatment capacity", "Not assessing for elder abuse"], [{question: "What are ADLs and IADLs?", answer: "Activities of Daily Living (bathing, dressing, eating, toileting, transferring, continence) and Instrumental Activities (cooking, cleaning, managing finances, medication management, transportation). They measure functional capacity."}, {question: "Why is depression underdiagnosed in older adults?", answer: "Older adults may present with somatic complaints rather than sadness, symptoms may be attributed to normal aging, and screening may not be routine in geriatric settings."}]),

  e("oppression-and-privilege", "Oppression and Privilege", "Cultural Competence", "Oppression and Privilege | ASWB Guide", "Learn about oppression, privilege, and anti-oppressive practice for the ASWB exam.", ["oppression", "privilege", "anti-oppressive practice", "social justice", "ASWB"], "Social workers must understand systems of oppression and privilege and practice in ways that challenge, rather than reproduce, inequality.", "Key concepts: oppression (systematic disadvantage based on social group membership), privilege (unearned advantages based on social group membership), power (capacity to influence outcomes), and intersectionality (overlapping systems of oppression). Forms of oppression: personal (individual attitudes/behaviors), institutional (organizational policies/practices), and structural/cultural (societal values and norms that perpetuate inequality). Anti-oppressive practice requires critical self-reflection on one's own social location and privilege.", "Oppression and privilege are tested on the ASWB exam in diversity and social justice contexts.", "Oppression operates at personal, institutional, and structural levels. People can simultaneously experience oppression and privilege based on different aspects of their identity.", "Assess how systems of oppression and privilege affect the client's presenting problems, access to resources, and experiences with helping systems.", "Anti-oppressive practice: critical self-reflection, challenge systemic barriers, advocate for policy change, center marginalized voices, address power differentials in the therapeutic relationship.", "Ignoring systems of oppression leads to blaming clients for structural barriers. Failing to examine one's own privilege can perpetuate oppressive dynamics in the therapeutic relationship.", ["Oppression operates at personal, institutional, and structural levels", "Anti-oppressive practice requires critical self-reflection", "People can experience oppression and privilege simultaneously", "Social workers must challenge, not reproduce, inequality"], ["Ignoring how oppression affects the client's presenting problem", "Not examining one's own privilege and biases", "Blaming clients for structural barriers"], [{question: "What is anti-oppressive practice?", answer: "An approach requiring critical self-reflection on one's own social location and privilege, challenging systemic barriers, centering marginalized voices, and working toward structural change."}, {question: "Can someone have both oppression and privilege?", answer: "Yes. Intersectionality recognizes that people hold multiple social identities simultaneously and may experience both oppression and privilege based on different aspects of their identity."}]),

  e("evidence-based-practice-process", "Evidence-Based Practice Process", "Research Methods", "Evidence-Based Practice Process | ASWB Guide", "Learn about the evidence-based practice process in social work for the ASWB exam.", ["evidence-based practice", "EBP process", "research utilization", "ASWB"], "Evidence-based practice (EBP) in social work integrates the best available research evidence with clinical expertise and client values/preferences to guide practice decisions.", "The EBP process: (1) Formulate a clear, answerable practice question (PICO format: Population, Intervention, Comparison, Outcome). (2) Search for the best available evidence. (3) Critically appraise the evidence for validity and applicability. (4) Apply evidence integrated with clinical expertise and client preferences. (5) Evaluate the outcome. Levels of evidence hierarchy: systematic reviews/meta-analyses (highest), RCTs, quasi-experimental studies, cohort studies, case studies, expert opinion (lowest).", "EBP is tested on the ASWB exam in research and practice contexts.", "EBP requires balancing research evidence with clinical expertise and client values. It is not cookbook practice that ignores clinical judgment or client preferences.", "Formulate practice questions, search databases (PubMed, Cochrane), and evaluate the quality and applicability of available evidence.", "Apply evidence-informed interventions, monitor client outcomes, and adjust practice based on results.", "Applying research without considering client values and cultural context undermines the therapeutic alliance and may reduce effectiveness.", ["EBP integrates research, clinical expertise, and client values", "PICO format structures practice questions", "Systematic reviews are the highest level of evidence", "EBP is not cookbook practice"], ["Applying research without considering client preferences", "Equating EBP with only using manualized treatments", "Not knowing the levels of evidence hierarchy"], [{question: "What are the five steps of EBP?", answer: "Ask a practice question (PICO), search for evidence, critically appraise the evidence, apply it with clinical expertise and client values, and evaluate the outcome."}, {question: "What is PICO?", answer: "A format for structuring practice questions: Population, Intervention, Comparison, and Outcome."}]),

  e("community-development", "Community Development", "Community Practice", "Community Development | ASWB Guide", "Learn about community development approaches for the ASWB exam.", ["community development", "capacity building", "community organization", "ASWB"], "Community development is a process by which communities strengthen their capacity to identify and address their own needs, leveraging internal assets and building collective power.", "Three community organization models (Rothman): locality development (consensus building, participation, capacity), social planning (expert-driven, data-based, rational problem-solving), and social action (confrontation, advocacy, power redistribution). Asset-based community development (ABCD) focuses on community strengths rather than deficits. Key principles: community self-determination, democratic participation, capacity building, and sustainability.", "Community practice models are tested on the ASWB exam.", "Community issues may include inadequate housing, healthcare access, food insecurity, environmental hazards, violence, and systemic discrimination.", "Community assessment identifies needs, assets, stakeholders, power structures, and readiness for change.", "Facilitate community participation, build coalitions, develop local leadership, connect to resources, and advocate for systemic change.", "Expert-driven approaches without community participation can create dependency rather than empowerment.", ["Rothman's three models: locality development, social planning, social action", "ABCD focuses on community strengths", "Community self-determination is a core principle", "Social action focuses on power redistribution"], ["Confusing the three community organization models", "Not understanding ABCD approach", "Not recognizing the importance of community participation"], [{question: "What are Rothman's three models?", answer: "Locality development (consensus/participation), social planning (expert-driven/rational), and social action (confrontation/power redistribution)."}, {question: "What is ABCD?", answer: "Asset-Based Community Development focuses on identifying and mobilizing community strengths and resources rather than focusing on deficits and needs."}]),

  e("acceptance-commitment-therapy", "Acceptance and Commitment Therapy", "Psychotherapy Approaches", "ACT in Social Work | ASWB Guide", "Learn about Acceptance and Commitment Therapy principles for the ASWB exam.", ["ACT", "acceptance and commitment therapy", "psychological flexibility", "mindfulness", "ASWB"], "ACT is a third-wave behavioral therapy that uses acceptance, mindfulness, and values-based action to promote psychological flexibility.", "Six core processes: acceptance (willingness to experience thoughts/feelings without trying to change them), cognitive defusion (separating from unhelpful thoughts), being present (mindful awareness), self-as-context (observing self separate from experiences), values (identifying what matters most), and committed action (taking values-consistent action despite discomfort). ACT is evidence-based for chronic pain, anxiety, depression, substance abuse, and OCD.", "ACT concepts are tested on the ASWB exam as a third-wave therapy.", "The goal of ACT is not symptom reduction per se, but increased psychological flexibility: the ability to contact the present moment and engage in values-directed action.", "Assess psychological flexibility, experiential avoidance patterns, values clarity, and functional impact of avoidance.", "Mindfulness exercises, cognitive defusion techniques, values clarification, and committed action planning.", "ACT is not about accepting harmful situations; it is about changing one's relationship to internal experiences while taking effective action.", ["ACT promotes psychological flexibility", "Six core processes including acceptance, defusion, and values", "Goal is values-consistent action, not just symptom reduction", "Third-wave behavioral therapy incorporating mindfulness"], ["Confusing ACT with passive acceptance of harmful situations", "Not understanding psychological flexibility", "Confusing ACT with traditional CBT"], [{question: "What is psychological flexibility?", answer: "The ability to be present, open to internal experiences, and engaged in values-directed action, even in the presence of difficult thoughts and feelings."}, {question: "How is ACT different from traditional CBT?", answer: "CBT focuses on changing thought content. ACT focuses on changing one's relationship to thoughts (defusion) and engaging in values-based action despite difficult internal experiences."}]),

  e("family-life-cycle", "Family Life Cycle", "Family Systems", "Family Life Cycle Stages | ASWB Guide", "Learn about family life cycle stages and transitions for the ASWB exam.", ["family life cycle", "Carter and McGoldrick", "family stages", "transitions", "ASWB"], "The family life cycle (Carter and McGoldrick) describes predictable stages families move through, each requiring emotional and structural adjustments.", "Stages: (1) Leaving home (single young adult), (2) Joining of families through marriage/union, (3) Families with young children, (4) Families with adolescents, (5) Launching children and moving on, (6) Families in later life. Each transition requires emotional processing and changes in family structure, roles, and relationships. Families may become stuck at transitions, producing symptoms. Non-traditional families (single parent, blended, same-sex, childless) follow variations of these stages.", "Family life cycle stages are tested on the ASWB exam.", "Symptoms often emerge during family life cycle transitions when the family has difficulty making the required adjustments.", "Assess where the family is in the life cycle, whether they are navigating a transition, and what adjustments are needed.", "Help families understand and navigate transitions, adjust roles and boundaries, and process the emotional demands of each stage.", "Applying a single-culture family life cycle model without cultural adaptation ignores diverse family forms.", ["Carter and McGoldrick developed the family life cycle model", "Symptoms often emerge at life cycle transitions", "Each stage requires emotional and structural adjustments", "Non-traditional families follow variations of these stages"], ["Not knowing the family life cycle stages", "Ignoring cultural variations in family development", "Not connecting symptoms to life cycle transitions"], [{question: "What are the family life cycle stages?", answer: "Leaving home, joining through marriage/union, families with young children, families with adolescents, launching children, and families in later life."}, {question: "Why do symptoms often appear at transitions?", answer: "Life cycle transitions require emotional processing and structural adjustments. When families struggle to make these adjustments, members may develop symptoms."}]),

  e("eating-disorders", "Eating Disorders", "Mental Health Disorders", "Eating Disorders | ASWB Guide", "Learn about eating disorders for the ASWB exam.", ["eating disorders", "anorexia", "bulimia", "binge eating", "ASWB"], "Eating disorders are serious mental health conditions characterized by disturbances in eating behaviors, body image, and weight regulation.", "DSM-5 eating disorders: Anorexia Nervosa (restriction, low body weight, intense fear of gaining weight, body image disturbance; restricting type or binge-purge type), Bulimia Nervosa (binge eating followed by compensatory behaviors such as purging, excessive exercise, fasting; at least weekly for 3 months), Binge Eating Disorder (recurrent binge episodes without compensatory behaviors; at least weekly for 3 months). Anorexia has the highest mortality rate of any mental health disorder.", "Eating disorders are tested on the ASWB exam in clinical assessment contexts.", "Signs include significant weight changes, preoccupation with food/weight/body, restrictive eating, binge eating, purging behaviors, excessive exercise, and medical complications.", "Assess eating patterns, body image, weight history, medical complications, co-occurring disorders, and family dynamics.", "CBT-E (Enhanced CBT for eating disorders), family-based treatment (Maudsley method for adolescents), nutritional counseling, medical monitoring, and medication when indicated.", "Anorexia has the highest mortality rate of any mental health disorder. Medical complications require monitoring.", ["Anorexia has the highest mortality rate of any mental illness", "Binge Eating Disorder is the most common eating disorder", "Family-based treatment (Maudsley) is effective for adolescent anorexia", "Eating disorders affect all genders and demographics"], ["Not knowing the differences between eating disorders", "Not recognizing that eating disorders can be life-threatening", "Assuming eating disorders only affect young white women"], [{question: "Which eating disorder has the highest mortality rate?", answer: "Anorexia Nervosa has the highest mortality rate of any mental health disorder, due to medical complications and suicide."}, {question: "What is the Maudsley method?", answer: "A family-based treatment for adolescent anorexia that empowers parents to take charge of their child's nutrition and weight restoration."}]),

  e("attention-deficit-disorders", "ADHD and Attention Disorders", "Mental Health Disorders", "ADHD | ASWB Guide", "Learn about ADHD for the ASWB exam.", ["ADHD", "attention deficit", "hyperactivity", "neurodevelopmental", "ASWB"], "ADHD is a neurodevelopmental disorder characterized by persistent inattention, hyperactivity, and impulsivity that interferes with functioning or development.", "DSM-5 presentations: Predominantly Inattentive (difficulty sustaining attention, following through, organizing), Predominantly Hyperactive-Impulsive (fidgeting, difficulty remaining seated, excessive talking, interrupting), Combined. Symptoms must be present before age 12, occur in 2+ settings, and cause functional impairment. ADHD persists into adulthood in 60% of cases. Treatment includes behavioral strategies, parent training, school accommodations, and medication (stimulants are first-line).", "ADHD is tested on the ASWB exam in neurodevelopmental contexts.", "Children: difficulty paying attention, excessive activity, impulsivity, academic difficulties. Adults: disorganization, difficulty completing tasks, time management problems, relationship difficulties.", "Comprehensive evaluation including developmental history, behavioral rating scales, school reports, and assessment in multiple settings.", "Behavioral interventions, parent training, school accommodations (504 plan or IEP), organizational skills training, and medication when indicated.", "Untreated ADHD significantly affects academic, social, and occupational functioning across the lifespan.", ["ADHD symptoms must be present before age 12", "Three presentations: inattentive, hyperactive-impulsive, combined", "ADHD persists into adulthood in approximately 60% of cases", "Assessment requires multiple settings and informants"], ["Not knowing DSM-5 ADHD criteria", "Assuming ADHD only affects children", "Not recognizing inattentive presentation without hyperactivity"], [{question: "What are the three ADHD presentations?", answer: "Predominantly Inattentive, Predominantly Hyperactive-Impulsive, and Combined Presentation."}, {question: "Does ADHD persist into adulthood?", answer: "Yes. Approximately 60% of children with ADHD continue to have significant symptoms in adulthood."}]),

  e("autism-spectrum-disorder", "Autism Spectrum Disorder", "Mental Health Disorders", "Autism Spectrum Disorder | ASWB Guide", "Learn about ASD for the ASWB exam.", ["autism", "ASD", "neurodevelopmental", "spectrum", "ASWB"], "Autism Spectrum Disorder is a neurodevelopmental condition characterized by persistent deficits in social communication and restricted, repetitive behaviors.", "DSM-5 combined previous subtypes (Autistic Disorder, Asperger's, PDD-NOS) into a single ASD diagnosis with severity levels (1-3). Two domains: social communication deficits and restricted/repetitive behaviors. Onset in early developmental period. Severity levels: Level 1 (requiring support), Level 2 (requiring substantial support), Level 3 (requiring very substantial support).", "ASD is tested on the ASWB exam, especially DSM-5 changes.", "Social communication challenges, repetitive behaviors, sensory sensitivities, difficulty with transitions, and special interests.", "Comprehensive developmental evaluation, standardized diagnostic tools, assessment across settings.", "Behavioral interventions (ABA), social skills training, speech-language therapy, occupational therapy, family support, and school accommodations.", "One-size-fits-all approaches are ineffective due to the wide spectrum of presentations.", ["DSM-5 combined previous subtypes into single ASD diagnosis", "Two domains: social communication and restricted/repetitive behaviors", "Three severity levels requiring different support", "Asperger's is no longer a separate diagnosis"], ["Not knowing DSM-5 changes to ASD classification", "Treating ASD as a single presentation", "Not understanding the spectrum concept"], [{question: "What changed about autism in DSM-5?", answer: "Previous subtypes (Autistic Disorder, Asperger's, PDD-NOS) were combined into a single Autism Spectrum Disorder diagnosis with three severity levels."}, {question: "What are the two core domains of ASD?", answer: "Persistent deficits in social communication/interaction and restricted, repetitive patterns of behavior, interests, or activities."}]),

  e("obsessive-compulsive-disorder", "Obsessive-Compulsive Disorder", "Mental Health Disorders", "OCD | ASWB Guide", "Learn about OCD for the ASWB exam.", ["OCD", "obsessions", "compulsions", "exposure response prevention", "ASWB"], "OCD is characterized by obsessions (intrusive, unwanted thoughts) and compulsions (repetitive behaviors performed to reduce anxiety).", "DSM-5 placed OCD in its own category (Obsessive-Compulsive and Related Disorders), separate from anxiety disorders. Common obsessions: contamination, symmetry, harm, forbidden thoughts. Common compulsions: washing, checking, counting, arranging. The anxiety cycle: obsession triggers anxiety, compulsion temporarily reduces anxiety, reinforcing the cycle. Exposure and Response Prevention (ERP) is the gold standard treatment.", "OCD is tested on the ASWB exam, including its DSM-5 reclassification.", "Recurrent obsessions cause marked anxiety; compulsions are performed to reduce this distress. Symptoms are time-consuming (1+ hour/day) and cause significant impairment.", "Assess obsessions, compulsions, time consumed, degree of resistance, level of control, and functional impairment. Yale-Brown OCD Scale (Y-BOCS) is the standard measure.", "ERP (graduated exposure to triggers while preventing compulsive response), CBT, medication (SSRIs at higher doses), and combination treatment.", "Reassurance-seeking from the therapist functions as a compulsion and should not be reinforced.", ["OCD is now separate from anxiety disorders in DSM-5", "ERP is the gold standard treatment", "Compulsions temporarily reduce but ultimately maintain anxiety", "Reassurance-seeking functions as a compulsion"], ["Confusing OCD with OCPD", "Not knowing OCD's DSM-5 reclassification", "Not understanding the anxiety-compulsion cycle"], [{question: "What is ERP?", answer: "Exposure and Response Prevention: the client is gradually exposed to obsession triggers while refraining from performing compulsions, breaking the anxiety reinforcement cycle."}, {question: "Is OCD still an anxiety disorder in DSM-5?", answer: "No. DSM-5 created a separate Obsessive-Compulsive and Related Disorders category."}]),

  e("social-work-research-design", "Research Design in Social Work", "Research Methods", "Research Design | ASWB Guide", "Learn about research designs for the ASWB exam.", ["research design", "experimental", "quasi-experimental", "single-subject", "ASWB"], "Understanding research design helps social workers evaluate evidence and conduct practice-relevant research.", "Experimental (RCT): random assignment to treatment/control groups, strongest causal evidence. Quasi-experimental: comparison groups without random assignment (e.g., nonequivalent groups, interrupted time series). Pre-experimental: one group pretest-posttest, no control group, weakest design. Single-subject designs (N=1): measure individual client outcomes over time using baseline and intervention phases (A-B, A-B-A-B). Correlational: examines relationships between variables without manipulation.", "Research designs are tested on the ASWB exam.", "Internal validity (confidence in causal conclusions) is highest in experimental designs. External validity (generalizability) may be higher in naturalistic designs.", "Select design based on research question, ethical constraints, and practical considerations.", "Implement design, collect data, analyze results, and interpret findings considering design limitations.", "Threats to validity include selection bias, maturation, history, and attrition.", ["RCTs provide the strongest causal evidence", "Quasi-experimental designs lack random assignment", "Single-subject designs measure individual client change", "Internal validity = causal confidence; external validity = generalizability"], ["Confusing experimental with quasi-experimental", "Not understanding single-subject designs", "Not knowing threats to validity"], [{question: "What makes a study experimental?", answer: "Random assignment of participants to treatment and control groups, allowing the researcher to draw causal conclusions."}, {question: "What is a single-subject design?", answer: "A research design that measures an individual client's outcomes over time, comparing baseline (A) and intervention (B) phases. Used to evaluate individual treatment effectiveness."}]),

  e("cultural-awareness-training", "Cultural Self-Awareness", "Cultural Competence", "Cultural Self-Awareness | ASWB Guide", "Learn about cultural self-awareness in social work for the ASWB exam.", ["cultural self-awareness", "implicit bias", "cultural competence", "ASWB"], "Cultural self-awareness is the foundation of culturally competent practice. Social workers must examine their own cultural identity, values, biases, and privileges.", "NASW Standards for Cultural Competence require social workers to develop cultural self-awareness, cross-cultural knowledge, and culturally responsive skills. Implicit biases are unconscious attitudes affecting clinical decisions. Cultural self-awareness involves examining one's own worldview, recognizing how it differs from clients', and understanding how power and privilege operate in the helping relationship.", "Cultural self-awareness is tested on the ASWB exam as a component of cultural competence.", "Without cultural self-awareness, social workers risk imposing their own cultural values on clients, misinterpreting behavior, and making biased clinical decisions.", "Ongoing self-reflection, supervision, cultural immersion experiences, and implicit bias assessment.", "Critical self-reflection, cultural supervision, continuing education, community engagement, and seeking feedback from clients and colleagues.", "Failure to examine one's own biases leads to culturally incompetent and potentially harmful practice.", ["Cultural self-awareness is the foundation of cultural competence", "Implicit biases affect clinical decisions unconsciously", "Self-reflection is an ongoing process, not a one-time activity", "NASW Standards require cultural competence"], ["Assuming cultural competence means knowing about other cultures without examining one's own", "Not recognizing implicit biases", "Treating cultural competence as a destination rather than a journey"], [{question: "What is cultural self-awareness?", answer: "The process of examining one's own cultural identity, values, biases, and privileges and understanding how they affect clinical practice."}, {question: "What are implicit biases?", answer: "Unconscious attitudes and stereotypes that affect perceptions, decisions, and behaviors, including clinical judgment and treatment decisions."}]),

  e("social-work-with-groups-leadership", "Group Leadership Skills", "Group Work", "Group Leadership Skills | ASWB Guide", "Learn about essential group leadership skills for the ASWB exam.", ["group leadership", "facilitation", "group skills", "ASWB"], "Effective group leadership requires specific skills beyond individual therapy competencies. The group leader manages group dynamics while facilitating therapeutic change.", "Essential skills: active listening, linking (connecting member experiences), blocking (stopping harmful interactions), drawing out (encouraging quiet members), modeling (demonstrating desired behaviors), processing (helping the group reflect on interactions), summarizing, and confronting (challenging incongruence). Leadership styles: authoritarian (directive), democratic (collaborative), laissez-faire (minimal direction). Most effective leaders adapt their style to the group's stage and needs.", "Group leadership skills are tested on the ASWB exam.", "Leaders must balance attending to individual members with monitoring group process. Different stages require different leadership emphasis.", "Assess group dynamics, individual member needs, stage of development, and any problematic patterns.", "Apply leadership skills flexibly, adapt style to group stage, address dynamics in real time, and seek supervision.", "Passive leadership allows negative dynamics to develop. Over-directive leadership prevents member autonomy.", ["Linking connects member experiences to build universality", "Blocking stops harmful interactions while maintaining respect", "Leadership style should adapt to group stage and needs", "Processing helps the group reflect on their interactions"], ["Not knowing specific group leadership skills", "Applying a single leadership style regardless of context", "Allowing harmful interactions without blocking"], [{question: "What is linking in group work?", answer: "Connecting the experiences, themes, or feelings of different group members to build universality and cohesion."}, {question: "What is blocking?", answer: "A leadership skill used to stop harmful interactions (scapegoating, monopolizing, breaching confidentiality) while maintaining respect for all members."}]),

  e("vicarious-trauma", "Vicarious Trauma and Secondary Traumatic Stress", "Ethics & Legal Issues", "Vicarious Trauma | ASWB Guide", "Learn about vicarious trauma and compassion fatigue for the ASWB exam.", ["vicarious trauma", "secondary traumatic stress", "compassion fatigue", "burnout", "ASWB"], "Vicarious trauma occurs when exposure to clients' traumatic material causes shifts in the worker's worldview, beliefs, and psychological functioning.", "Related concepts: Vicarious traumatization (cumulative shift in worldview from empathic engagement with trauma survivors), secondary traumatic stress (STS: acute trauma symptoms from hearing about client trauma), compassion fatigue (emotional exhaustion from chronic empathy), and burnout (chronic workplace stress leading to emotional exhaustion, depersonalization, and reduced accomplishment). Self-care, supervision, and organizational support are protective factors.", "Vicarious trauma is tested on the ASWB exam in ethics and professional practice contexts.", "Symptoms include intrusive thoughts about client material, avoidance, emotional numbing, cynicism, decreased empathy, difficulty maintaining boundaries, and changes in worldview (safety, trust).", "Monitor for signs of vicarious trauma through self-awareness, supervision, and organizational assessment.", "Self-care strategies, regular supervision, peer support, workload management, continuing education, and organizational wellness initiatives.", "Unaddressed vicarious trauma leads to impaired practice, ethical violations, and harm to clients.", ["Vicarious trauma shifts worldview; STS causes acute symptoms", "Supervision and self-care are protective factors", "Organizations have responsibility for worker wellness", "Burnout involves exhaustion, depersonalization, and reduced accomplishment"], ["Confusing vicarious trauma with burnout", "Not recognizing symptoms of secondary traumatic stress", "Treating self-care as solely the individual worker's responsibility"], [{question: "What is the difference between vicarious trauma and burnout?", answer: "Vicarious trauma involves changes in worldview from exposure to client trauma. Burnout results from chronic workplace stress and involves emotional exhaustion, depersonalization, and reduced accomplishment."}, {question: "What is compassion fatigue?", answer: "The emotional exhaustion that results from chronic empathic engagement with suffering clients. It combines elements of secondary traumatic stress and burnout."}]),

  e("solution-focused-brief-therapy-techniques", "Solution-Focused Brief Therapy Techniques", "Psychotherapy Approaches", "SFBT Techniques | ASWB Guide", "Learn about SFBT techniques and principles for the ASWB exam.", ["SFBT", "solution-focused", "miracle question", "scaling", "Steve de Shazer", "ASWB"], "Solution-Focused Brief Therapy (de Shazer and Berg) is a strengths-based, goal-oriented approach that focuses on solutions rather than problems.", "Key principles: if it works, do more of it; if it does not work, do something different; small changes lead to larger changes. Core techniques: miracle question, exception questions (when is the problem absent?), scaling questions (1-10 ratings of progress), coping questions (how have you managed?), compliments, and the first session formula task. The therapist adopts a not-knowing, curious stance and positions the client as the expert.", "SFBT is tested on the ASWB exam.", "Clients define their own goals and identify existing solutions and strengths.", "Focus on client goals, exceptions, strengths, and coping rather than problem analysis.", "Brief (typically 3-8 sessions), goal-oriented, and collaborative. Between-session tasks reinforce progress.", "Insufficient alone for clients with active safety concerns, severe mental illness, or complex trauma.", ["Focus on solutions, not problems", "Client is the expert on their own life", "Miracle question helps envision the preferred future", "Small changes lead to larger changes"], ["Confusing SFBT with narrative therapy", "Spending too much time on problem analysis", "Not understanding the miracle question"], [{question: "What is the miracle question?", answer: "If a miracle happened tonight and the problem was solved, what would be different? It helps clients describe their preferred future in concrete, behavioral terms."}, {question: "Who developed SFBT?", answer: "Steve de Shazer and Insoo Kim Berg developed SFBT at the Brief Family Therapy Center in Milwaukee."}]),

  e("gestalt-therapy", "Gestalt Therapy", "Psychotherapy Approaches", "Gestalt Therapy | ASWB Guide", "Learn about gestalt therapy principles for the ASWB exam.", ["gestalt therapy", "Fritz Perls", "here and now", "empty chair", "ASWB"], "Gestalt therapy (Fritz Perls) emphasizes present-moment awareness, personal responsibility, and the integration of fragmented aspects of the self.", "Key concepts: here-and-now focus (what is happening in the present moment), awareness (attending to thoughts, feelings, and sensations), unfinished business (unresolved past issues affecting present functioning), contact/withdrawal cycle, and organismic self-regulation. Techniques: empty chair (dialogue with absent person or aspect of self), exaggeration (amplifying a gesture or statement to increase awareness), I-statements (taking responsibility for one's experience), and experiments (trying new behaviors in session).", "Gestalt therapy is tested on the ASWB exam.", "Clients present with unfinished business, avoidance of feelings, and difficulty being fully present.", "Focus on what the client is doing, feeling, and experiencing in the present moment.", "Empty chair, exaggeration, focusing on body language, I-statements, and phenomenological exploration.", "Premature confrontation or pushing awareness before the client is ready can be overwhelming.", ["Here-and-now focus is central to gestalt therapy", "Empty chair technique facilitates dialogue with absent others", "Awareness is the primary therapeutic mechanism", "Fritz Perls developed gestalt therapy"], ["Confusing gestalt with psychodynamic therapy", "Not knowing the empty chair technique", "Confusing gestalt therapy with Gestalt psychology"], [{question: "What is the empty chair technique?", answer: "The client engages in dialogue with an imagined person (or aspect of self) seated in an empty chair, facilitating expression of unresolved feelings and unfinished business."}, {question: "What is the focus of gestalt therapy?", answer: "Present-moment awareness. Rather than analyzing the past, gestalt therapy focuses on what the client is experiencing right now and increasing awareness of thoughts, feelings, and sensations."}]),

  e("feminist-therapy", "Feminist Therapy", "Psychotherapy Approaches", "Feminist Therapy | ASWB Guide", "Learn about feminist therapy principles for the ASWB exam.", ["feminist therapy", "gender", "power analysis", "empowerment", "ASWB"], "Feminist therapy examines how gender, power, and sociopolitical factors affect mental health and the therapeutic relationship.", "Key principles: the personal is political (individual problems are connected to social/political structures), egalitarian therapeutic relationship (minimizing power differential), gender role analysis (examining how gender expectations affect functioning), power analysis (understanding how power operates), and empowerment (building client agency). Feminist therapy challenges traditional diagnostic categories as potentially pathologizing normal responses to oppression.", "Feminist therapy principles are tested on the ASWB exam.", "Clients may present with issues related to gender role constraints, intimate partner violence, sexual harassment, workplace discrimination, and body image.", "Assessment includes examining the impact of gender socialization, power dynamics, and sociopolitical factors on the presenting problem.", "Consciousness raising, gender role analysis, power analysis, bibliotherapy, assertiveness training, and advocacy.", "Applying feminist therapy without cultural sensitivity can impose Western feminist values on clients from other cultural contexts.", ["The personal is political", "Therapeutic relationship should be egalitarian", "Gender role analysis examines how gender expectations affect functioning", "Power analysis is a core component"], ["Not understanding feminist therapy principles", "Confusing feminist therapy with only serving women", "Not recognizing the political dimension of personal problems"], [{question: "What does 'the personal is political' mean?", answer: "Individual problems are connected to broader social and political structures. Personal distress often reflects systemic inequality rather than individual pathology."}, {question: "Is feminist therapy only for women?", answer: "No. Feminist therapy examines how gender, power, and sociopolitical factors affect all people, regardless of gender identity."}]),

  e("existential-therapy", "Existential Therapy", "Psychotherapy Approaches", "Existential Therapy | ASWB Guide", "Learn about existential therapy concepts for the ASWB exam.", ["existential therapy", "Yalom", "meaning", "death anxiety", "freedom", "ASWB"], "Existential therapy addresses fundamental concerns of human existence: death, freedom, isolation, and meaninglessness.", "Irvin Yalom identified four ultimate concerns: death (awareness of mortality), freedom (responsibility for choices), existential isolation (fundamental aloneness), and meaninglessness (the search for purpose). Viktor Frankl's logotherapy specifically focuses on finding meaning. Existential therapy emphasizes authentic living, personal responsibility, and confronting existential anxiety rather than avoiding it.", "Existential concepts are tested on the ASWB exam.", "Clients may present with existential crises, loss of meaning, fear of death, difficulty making choices, and feelings of isolation.", "Explore the client's relationship to the four ultimate concerns and how existential anxiety manifests.", "Facilitate exploration of meaning, authentic choice-making, acceptance of mortality, and connection despite existential isolation.", "Existential therapy may not provide the structured interventions needed for acute symptom management.", ["Four ultimate concerns: death, freedom, isolation, meaninglessness", "Frankl's logotherapy focuses on finding meaning", "Authenticity and personal responsibility are central", "Yalom identified the four ultimate concerns"], ["Not knowing Yalom's four ultimate concerns", "Confusing existential with humanistic therapy", "Not understanding existential isolation"], [{question: "What are Yalom's four ultimate concerns?", answer: "Death (mortality awareness), freedom (responsibility for choices), existential isolation (fundamental aloneness), and meaninglessness (the search for purpose)."}, {question: "What is logotherapy?", answer: "Viktor Frankl's therapeutic approach focusing on finding meaning in life, even in suffering. Frankl developed logotherapy based on his experiences in Nazi concentration camps."}]),

  e("social-work-in-criminal-justice", "Social Work in Criminal Justice", "Community Practice", "Criminal Justice Social Work | ASWB Guide", "Learn about social work in the criminal justice system for the ASWB exam.", ["criminal justice", "forensic social work", "reentry", "restorative justice", "ASWB"], "Social workers in criminal justice settings provide services to individuals involved in the justice system, including assessment, treatment, advocacy, and reentry support.", "Practice areas include juvenile justice, adult corrections, probation/parole, drug courts, mental health courts, victim services, and forensic evaluation. Restorative justice focuses on repairing harm rather than punishment, involving victims, offenders, and the community. Social workers address criminogenic needs (factors contributing to criminal behavior): antisocial cognition, antisocial associates, substance abuse, family dysfunction, employment instability, and mental health issues.", "Criminal justice social work is tested on the ASWB exam.", "Justice-involved individuals face high rates of mental illness, substance use, trauma, homelessness, and difficulty accessing services upon reentry.", "Comprehensive biopsychosocial assessment, risk-need-responsivity assessment, and evaluation of criminogenic needs.", "Cognitive-behavioral interventions, substance abuse treatment, trauma-informed care, reentry planning, family engagement, and advocacy for alternatives to incarceration.", "Dual-role conflicts between social work values (client-centered) and system demands (public safety) require careful ethical navigation.", ["Restorative justice focuses on repairing harm, not punishment", "Criminogenic needs are factors contributing to criminal behavior", "Justice-involved populations have high rates of mental illness and trauma", "Social workers face dual-role ethical conflicts in justice settings"], ["Not understanding restorative justice principles", "Not recognizing the high prevalence of mental illness in justice populations", "Not navigating the dual-role conflict between client welfare and public safety"], [{question: "What is restorative justice?", answer: "An approach focusing on repairing harm caused by criminal behavior through processes involving victims, offenders, and the community, rather than focusing solely on punishment."}, {question: "What are criminogenic needs?", answer: "Factors that contribute to criminal behavior and can be changed through intervention: antisocial cognition, antisocial associates, substance abuse, family dysfunction, employment instability, and mental health issues."}]),

  e("social-work-private-practice", "Social Work Private Practice", "Community Practice", "Private Practice | ASWB Guide", "Learn about social work private practice for the ASWB exam.", ["private practice", "LCSW", "insurance panels", "business practices", "ASWB"], "Social workers in private practice provide clinical services independently, requiring advanced licensure (typically LCSW) and knowledge of business operations.", "Private practice requirements include clinical licensure, malpractice insurance, business registration, HIPAA compliance, and understanding of insurance billing and credentialing. Ethical considerations include appropriate scope of practice, maintaining competence, supervision (for pre-licensed clinicians), record keeping, and managing dual relationships in small communities. Third-party reimbursement requires understanding of managed care, prior authorization, CPT codes, and medical necessity.", "Private practice is tested on the ASWB exam in professional practice contexts.", "Private practitioners manage all aspects of their practice including marketing, scheduling, billing, clinical documentation, and continuing education.", "Assess readiness for independent practice including clinical competence, business skills, and financial sustainability.", "Establish business structure, secure insurance, credential with panels, develop policies and procedures, maintain competence through CE and consultation.", "Practicing beyond competence, inadequate record keeping, and poor boundary management increase liability risk.", ["LCSW is typically required for independent private practice", "Malpractice insurance is essential", "HIPAA compliance is required", "Understanding insurance billing and managed care is necessary"], ["Not knowing licensing requirements for private practice", "Not understanding insurance billing basics", "Not maintaining appropriate professional boundaries"], [{question: "What licensure is needed for private practice?", answer: "Typically LCSW (Licensed Clinical Social Worker) or equivalent clinical license, which requires an MSW, supervised clinical experience, and passing the clinical ASWB exam."}, {question: "What insurance is needed?", answer: "Professional liability (malpractice) insurance is essential to protect against claims of professional negligence."}]),

  e("single-subject-design", "Single-Subject Research Design", "Research Methods", "Single-Subject Design | ASWB Guide", "Learn about single-subject research designs for the ASWB exam.", ["single-subject design", "N=1", "A-B design", "baseline", "ASWB"], "Single-subject designs measure individual client change over time, making them highly applicable to clinical social work practice.", "Common designs: A-B (simplest: baseline then intervention), A-B-A (withdrawal: baseline, intervention, withdrawal to test causation), A-B-A-B (strengthened withdrawal design), multiple baseline (across behaviors, settings, or clients). The A phase is baseline (no intervention), B phase is intervention. Visual analysis of graphed data is the primary analysis method. Advantages: practical for individual practice evaluation, no control group needed, each client serves as their own control.", "Single-subject designs are tested on the ASWB exam as the most practice-relevant research design.", "Repeated measurement of the target behavior during baseline and intervention phases allows the practitioner to evaluate treatment effectiveness for individual clients.", "Establish stable baseline measurement before introducing the intervention. Define target behavior operationally.", "Collect data consistently, graph results, visually analyze for level, trend, and variability changes between phases.", "A-B designs cannot establish causation (only association). A-B-A withdrawal designs raise ethical concerns about removing effective treatment.", ["A-B is the most basic design: baseline then intervention", "A-B-A withdrawal design tests causation by removing intervention", "Each client serves as their own control", "Visual analysis of graphed data is the primary analysis method"], ["Confusing single-subject designs with case studies", "Not understanding baseline requirements", "Not knowing the difference between A-B and A-B-A designs"], [{question: "What is an A-B design?", answer: "The simplest single-subject design: A (baseline measurement with no intervention) followed by B (measurement during intervention). It cannot establish causation."}, {question: "What is the ethical concern with A-B-A designs?", answer: "Withdrawing an effective intervention during the second A phase raises ethical concerns about denying treatment. A-B-A-B designs address this by reinstating the intervention."}]),

  e("reality-therapy", "Reality Therapy", "Psychotherapy Approaches", "Reality Therapy | ASWB Guide", "Learn about reality therapy and choice theory for the ASWB exam.", ["reality therapy", "William Glasser", "choice theory", "WDEP", "ASWB"], "Reality therapy (William Glasser) is based on choice theory, emphasizing that all behavior is purposeful and chosen to satisfy five basic needs.", "Five basic needs: survival, love/belonging, power/achievement, freedom/autonomy, and fun/enjoyment. Choice theory holds that we can only control our own behavior, not others. The WDEP system: Wants (what do you want?), Doing (what are you doing?), Evaluation (is what you are doing helping you get what you want?), Planning (what is your plan?). Total behavior has four components: acting, thinking, feeling, and physiology.", "Reality therapy is tested on the ASWB exam.", "Focus on current behavior and choices rather than past experiences or unconscious processes.", "Assess current behavior, desired outcomes, and the gap between what the client wants and what they are doing.", "Use the WDEP system to help clients evaluate their behavior and develop action plans.", "Reality therapy may oversimplify complex problems and dismiss the role of past experiences.", ["Five basic needs: survival, love/belonging, power, freedom, fun", "We can only control our own behavior", "WDEP: Wants, Doing, Evaluation, Planning", "Focus on present behavior and choices"], ["Not knowing the WDEP system", "Confusing reality therapy with CBT", "Not knowing Glasser's five basic needs"], [{question: "What is the WDEP system?", answer: "A questioning framework: Wants (what do you want?), Doing (what are you doing?), Evaluation (is it working?), Planning (what can you do differently?)."}, {question: "What is choice theory?", answer: "Glasser's theory that all behavior is purposeful and chosen to satisfy five basic needs. We can only control our own behavior, not others."}]),

  e("crisis-hotlines-resources", "Crisis Resources and Hotlines", "Crisis Intervention", "Crisis Resources | ASWB Guide", "Learn about crisis resources and hotlines for social work practice and the ASWB exam.", ["988", "crisis hotline", "crisis resources", "National Suicide Prevention Lifeline", "ASWB"], "Social workers must know key crisis resources and how to connect clients with appropriate emergency services.", "Key resources: 988 Suicide and Crisis Lifeline (call or text 988, replaced 1-800-273-8255), Crisis Text Line (text HOME to 741741), National Domestic Violence Hotline (1-800-799-7233), SAMHSA National Helpline (1-800-662-4357), Trevor Project for LGBTQ+ youth (1-866-488-7386), and local mobile crisis teams. Social workers should maintain current knowledge of local crisis resources.", "Crisis resources are tested on the ASWB exam in crisis intervention contexts.", "Clients in crisis need immediate access to appropriate resources. Social workers should provide crisis numbers proactively.", "Assess crisis severity, immediate safety, support systems, and appropriate level of intervention.", "Connect clients with appropriate crisis resources, develop safety plans that include crisis numbers, and follow up after crisis referrals.", "Providing resources without follow-up or assessment may be insufficient for high-risk clients.", ["988 is the national Suicide and Crisis Lifeline", "Crisis Text Line: text HOME to 741741", "Know local crisis resources in your community", "Safety plans should include crisis hotline numbers"], ["Not knowing the 988 number", "Not following up after crisis referrals", "Providing hotline numbers without conducting a risk assessment"], [{question: "What is 988?", answer: "The national Suicide and Crisis Lifeline number, available for call or text, replacing the previous 1-800-273-8255 number."}, {question: "What is the Crisis Text Line?", answer: "A free, 24/7 crisis support service. Text HOME to 741741 to connect with a trained crisis counselor."}]),

  e("diversity-inclusion-practice", "Diversity and Inclusion in Practice", "Cultural Competence", "Diversity and Inclusion | ASWB Guide", "Learn about diversity and inclusion principles in social work for the ASWB exam.", ["diversity", "inclusion", "equity", "social justice", "ASWB"], "Diversity and inclusion are foundational to social work practice. The profession is committed to serving diverse populations and promoting equity.", "NASW Standards for Cultural Competence guide practice with diverse populations. Key concepts: diversity (the full range of human differences), inclusion (creating environments where all people feel valued), equity (fair distribution of resources addressing systemic disparities), cultural responsiveness (adapting services to meet diverse needs), and social identity (the interplay of race, ethnicity, gender, sexual orientation, disability, religion, socioeconomic status, and other identities).", "Diversity and inclusion are tested across the ASWB exam.", "Social workers must recognize their own social location and how it affects the therapeutic relationship.", "Assess cultural factors affecting the client, barriers to service access, and the cultural responsiveness of available services.", "Culturally responsive services, interpreter services, diverse staffing, inclusive policies, and ongoing cultural competence training.", "Color-blind approaches ignore the real impact of race and other identities on client experiences.", ["Diversity encompasses the full range of human differences", "Equity addresses systemic disparities, not just equal treatment", "Color-blind approaches ignore real impacts of identity", "Cultural competence is an ongoing process"], ["Treating all clients the same without considering cultural factors", "Assuming one's own cultural framework is universal", "Not recognizing systemic barriers to service access"], [{question: "What is the difference between equity and equality?", answer: "Equality means treating everyone the same. Equity means providing what each person needs to achieve fair outcomes, addressing systemic disparities."}, {question: "Why is a color-blind approach problematic?", answer: "It ignores the real impact of race and other identities on people's experiences, denies the existence of systemic racism, and prevents addressing disparities."}]),

  e("psychosocial-assessment", "Psychosocial Assessment", "Clinical Assessment", "Psychosocial Assessment | ASWB Guide", "Learn about comprehensive psychosocial assessment in social work for the ASWB exam.", ["psychosocial assessment", "biopsychosocial", "intake assessment", "ASWB"], "The psychosocial assessment is the foundation of social work practice, providing a comprehensive understanding of the client's biological, psychological, and social functioning.", "Components include: identifying information, presenting problem (in the client's own words), history of present problem, psychiatric/mental health history, medical history, substance use history, family history and dynamics, social/interpersonal relationships, education and employment, cultural and spiritual factors, legal issues, strengths and resources, and clinical impressions. The biopsychosocial model (Engel) integrates biological, psychological, and social factors.", "Psychosocial assessment is foundational to social work and tested on the ASWB exam.", "Assessment should capture the client's presenting concern, relevant history, current functioning, support systems, and goals.", "Use open-ended questions, active listening, and systematic inquiry across domains. Integrate information from multiple sources.", "Assessment informs diagnosis, treatment planning, and goal-setting. It should be documented clearly and updated as new information emerges.", "Incomplete assessment leads to inaccurate diagnoses and ineffective treatment plans.", ["The biopsychosocial model integrates biological, psychological, and social factors", "Assessment includes strengths alongside challenges", "Document the presenting problem in the client's own words", "Assessment is ongoing, not a one-time event"], ["Not conducting a comprehensive assessment before developing a treatment plan", "Focusing only on the presenting problem without exploring context", "Not including strengths in the assessment"], [{question: "What is the biopsychosocial model?", answer: "George Engel's model integrating biological (medical, genetic), psychological (cognitive, emotional, behavioral), and social (family, community, cultural) factors in understanding health and illness."}, {question: "What should be included in a psychosocial assessment?", answer: "Presenting problem, relevant history, mental health and substance use history, medical history, family dynamics, social relationships, cultural factors, strengths, and clinical impressions."}]),

  e("treatment-planning", "Treatment Planning", "Clinical Assessment", "Treatment Planning | ASWB Guide", "Learn about treatment planning in social work for the ASWB exam.", ["treatment planning", "treatment goals", "objectives", "interventions", "ASWB"], "Treatment planning is a collaborative process of developing a structured plan for addressing the client's identified needs and goals.", "Components: identified problems/needs (based on assessment), goals (broad desired outcomes), objectives (specific, measurable steps toward goals using SMART criteria), interventions (specific techniques and services), responsible parties, target dates, and criteria for discharge/completion. Treatment plans should be client-centered, culturally responsive, and based on evidence-based practice.", "Treatment planning is tested on the ASWB exam.", "Goals are broad and long-term. Objectives are specific, measurable, and time-limited. Interventions are the specific actions taken to achieve objectives.", "Collaborate with the client to identify priorities, set goals, and develop objectives. Review assessment findings and select evidence-based interventions.", "Develop a written plan, review regularly, modify based on client progress, and document all changes. Involve the client in all planning decisions.", "Plans developed without client input reduce engagement. Vague goals without measurable objectives cannot be evaluated.", ["Goals are broad; objectives are specific and measurable", "Treatment plans should be collaborative and client-centered", "Regular review and modification are essential", "Use SMART criteria for objectives"], ["Writing vague, unmeasurable goals", "Not involving the client in treatment planning", "Not reviewing and updating the plan regularly"], [{question: "What is the difference between goals and objectives?", answer: "Goals are broad, long-term desired outcomes. Objectives are specific, measurable, time-limited steps toward achieving goals."}, {question: "What are SMART objectives?", answer: "Specific, Measurable, Achievable, Relevant, and Time-bound. They provide clear criteria for evaluating progress."}]),

  e("trauma-and-resilience", "Trauma and Resilience", "Crisis Intervention", "Trauma and Resilience | ASWB Guide", "Learn about trauma, resilience, and protective factors for the ASWB exam.", ["trauma", "resilience", "protective factors", "ACEs", "ASWB"], "Understanding both trauma and resilience is essential for social work practice. Resilience is the capacity to recover, adapt, and thrive despite adversity.", "Trauma types: acute (single event), chronic (repeated), complex (multiple, interpersonal, often developmental), historical/intergenerational (collective trauma transmitted across generations). Resilience factors: individual (coping skills, self-efficacy, temperament), relational (secure attachment, supportive relationships), community (social cohesion, access to resources), and cultural (cultural identity, spirituality). ACEs research shows that protective factors (nurturing relationships, community support) can buffer the impact of adverse experiences.", "Trauma and resilience are tested on the ASWB exam.", "Trauma responses vary widely. Not everyone exposed to trauma develops PTSD. Resilience is the most common outcome following adversity.", "Assess both trauma exposure and resilience factors. Identify existing strengths and protective factors alongside risks.", "Build on existing resilience, strengthen protective factors, provide trauma-informed services, and connect with community resources.", "Focusing only on trauma without recognizing resilience pathologizes normal responses and misses client strengths.", ["Resilience is the most common outcome following trauma", "Protective factors buffer the impact of adversity", "Historical/intergenerational trauma affects communities across generations", "Assess both trauma and resilience factors"], ["Assuming all trauma-exposed individuals develop PTSD", "Focusing only on deficits without recognizing resilience", "Not considering intergenerational trauma"], [{question: "What is resilience?", answer: "The capacity to recover, adapt, and thrive despite adversity. Resilience is influenced by individual, relational, community, and cultural protective factors."}, {question: "What is intergenerational trauma?", answer: "The transmission of trauma effects across generations, often affecting communities with histories of collective trauma such as slavery, genocide, colonization, and forced relocation."}]),

  e("social-determinants-of-health", "Social Determinants of Health", "Policy & Advocacy", "Social Determinants of Health | ASWB Guide", "Learn about social determinants of health and their impact for the ASWB exam.", ["social determinants of health", "SDOH", "health equity", "health disparities", "ASWB"], "Social determinants of health (SDOH) are the conditions in which people are born, grow, live, work, and age that shape health outcomes.", "Key SDOH domains (Healthy People 2030): economic stability (poverty, employment, food security, housing stability), education access and quality, healthcare access and quality, neighborhood and built environment (transportation, safety, environmental conditions), and social and community context (social cohesion, discrimination, civic participation). SDOH account for 80-90% of modifiable contributors to health outcomes, far more than clinical care alone.", "SDOH are tested on the ASWB exam in policy and health contexts.", "Health disparities result from unequal distribution of SDOH across populations defined by race, ethnicity, socioeconomic status, geography, and other factors.", "Assess SDOH in all client encounters: housing, food security, transportation, employment, education, safety, and social support.", "Address SDOH through direct services (connecting to resources), community practice (improving conditions), and policy advocacy (addressing structural determinants).", "Clinical interventions alone are insufficient when SDOH are not addressed.", ["SDOH account for 80-90% of modifiable health contributors", "Five domains: economic stability, education, healthcare, neighborhood, social context", "Health disparities result from unequal SDOH distribution", "Social workers are uniquely positioned to address SDOH"], ["Not assessing SDOH in clinical encounters", "Focusing only on clinical interventions without addressing social factors", "Not recognizing the impact of SDOH on health outcomes"], [{question: "What are social determinants of health?", answer: "The conditions in which people are born, grow, live, work, and age that shape health outcomes, including economic stability, education, healthcare access, neighborhood conditions, and social context."}, {question: "Why are SDOH important for social workers?", answer: "SDOH account for 80-90% of modifiable health contributors. Social workers are uniquely positioned to assess and address these factors across micro, mezzo, and macro levels."}]),

  e("wraparound-services", "Wraparound Services", "Community Practice", "Wraparound Services | ASWB Guide", "Learn about the wraparound service model for the ASWB exam.", ["wraparound", "child mental health", "systems of care", "individualized", "ASWB"], "Wraparound is an intensive, individualized care planning and management process for children with complex emotional, behavioral, and mental health needs.", "Key principles: family voice and choice, team-based (natural supports plus professionals), individualized and strengths-based, community-based, culturally competent, and outcome-based. The wraparound process involves engagement, initial plan development, implementation, and transition. Wraparound teams include the family, natural supports, and representatives from involved systems (school, mental health, juvenile justice).", "Wraparound services are tested on the ASWB exam in child and community practice contexts.", "Children with complex needs often interact with multiple systems. Wraparound coordinates these systems around the family.", "Comprehensive strengths and needs assessment involving the family and all involved systems.", "Develop an individualized plan with the wraparound team, implement coordinated services, and monitor progress.", "Insufficient engagement of family voice leads to plans that do not reflect family priorities.", ["Family voice and choice drive the process", "Natural supports are included alongside professionals", "Wraparound is individualized and strengths-based", "The process coordinates multiple systems around the family"], ["Not understanding wraparound principles", "Not distinguishing wraparound from traditional case management", "Not including natural supports on the team"], [{question: "What is wraparound?", answer: "An intensive, individualized care planning process for children with complex needs that brings together family, natural supports, and system representatives to develop and implement a coordinated plan."}, {question: "How is wraparound different from case management?", answer: "Wraparound is more intensive, family-driven, and team-based than traditional case management. It emphasizes natural supports and coordinates across systems."}]),

  e("motivational-enhancement-therapy", "Motivational Enhancement Therapy", "Substance Abuse", "Motivational Enhancement Therapy | ASWB Guide", "Learn about MET for the ASWB exam.", ["MET", "motivational enhancement therapy", "motivation", "ambivalence", "ASWB"], "Motivational Enhancement Therapy (MET) is a systematic intervention based on motivational interviewing principles, specifically designed for substance use treatment.", "MET was developed for Project MATCH, a large NIAAA research study. It is a brief (typically 4 sessions), structured adaptation of MI that includes assessment feedback, personalized normative comparison, and a change plan. MET uses MI spirit and techniques (OARS, developing discrepancy) within a structured format. It is evidence-based for alcohol and drug use disorders.", "MET is tested on the ASWB exam in substance abuse treatment contexts.", "Clients present with ambivalence about changing substance use. MET addresses ambivalence through structured, empathic exploration.", "Comprehensive substance use assessment including standardized measures, followed by personalized feedback.", "Provide personalized assessment feedback, explore discrepancies between values and behavior, strengthen commitment to change, and develop a change plan.", "Confrontational approaches increase resistance and are counterproductive.", ["MET is a structured adaptation of MI for substance abuse", "Brief (typically 4 sessions) and evidence-based", "Developed for Project MATCH research", "Uses personalized feedback and normative comparison"], ["Confusing MET with MI (MI is a style; MET is a structured intervention)", "Using confrontational approaches", "Not understanding the role of assessment feedback in MET"], [{question: "How is MET different from MI?", answer: "MI is a counseling style/approach. MET is a specific, structured intervention (typically 4 sessions) that applies MI principles within a format including assessment feedback and personalized normative comparison."}, {question: "What was Project MATCH?", answer: "A large NIAAA research study that developed and tested MET as a treatment for alcohol use disorders, comparing it with CBT and 12-step facilitation."}]),

  e("quantitative-research-methods", "Quantitative Research Methods", "Research Methods", "Quantitative Research | ASWB Guide", "Learn about quantitative research methods for the ASWB exam.", ["quantitative research", "statistics", "sampling", "validity", "reliability", "ASWB"], "Quantitative research uses numerical data and statistical analysis to test hypotheses, measure outcomes, and establish generalizable findings.", "Key concepts: variables (independent, dependent, confounding), sampling (random, stratified, convenience, snowball), validity (internal: causal confidence; external: generalizability; construct: accuracy of measurement), reliability (consistency of measurement: test-retest, inter-rater, internal consistency). Descriptive statistics: mean, median, mode, standard deviation. Inferential statistics: t-test, ANOVA, chi-square, correlation, regression. Statistical significance (p < .05) indicates results unlikely due to chance.", "Quantitative research concepts are tested on the ASWB exam.", "Quantitative research tests hypotheses and measures relationships between variables using statistical analysis.", "Select appropriate design, sampling strategy, and measures based on the research question.", "Implement data collection, conduct statistical analysis, interpret results, and report findings with limitations.", "Correlation does not imply causation. Statistical significance does not equal clinical significance.", ["Random sampling supports generalizability", "Internal validity = causal confidence; external = generalizability", "Reliability = consistency of measurement", "p < .05 is the conventional threshold for statistical significance"], ["Confusing validity with reliability", "Assuming correlation means causation", "Not distinguishing statistical from clinical significance"], [{question: "What is the difference between validity and reliability?", answer: "Validity is whether a measure accurately measures what it claims to measure. Reliability is whether a measure produces consistent results over time or across raters."}, {question: "Does correlation equal causation?", answer: "No. Correlation indicates a relationship between variables but does not establish that one causes the other. Only experimental designs with random assignment can establish causation."}]),
];
